import type { Drill } from "./types";

// Industrial / mid drills, keyed by module slug — 25 per module.
// Line supervisor / production planner: shift handovers, downtime explanations,
// toolbox talks, maintenance coordination, quality holds, operator feedback,
// improvement pitches to the plant manager. Merged into course.ts.
export const INDUSTRIAL_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-mfg-mid-01","level":"mid","profession":"industrial","title":"The missed-target email that hides the number","scenario":"Your shift finished 340 units against a plan of 420 because the filler jammed twice. Your end-of-shift email to the plant manager opens with a paragraph about how hard the crew worked before mentioning the shortfall.","task":"Write a 2-3 sentence end-of-shift email that states the shortfall and cause in sentence one.","tips":["First sentence: the number missed and the reason.","The crew's effort is context, not the headline.","End with what you're doing about the jam."],"focus":["clarity","structure"],"placeholder":"We finished 340 of 420 — two filler jams cost us 90 minutes."},
    {"id":"lead-mfg-mid-02","level":"mid","profession":"industrial","title":"The radio call that buries the line-down","scenario":"Line 3 just stopped with a hydraulic leak and you need maintenance now. On the radio you start describing the noise the press was making before you say the line is actually down.","task":"Say a 2-sentence radio call that leads with the status and the ask.","tips":["First words: which line, down, and what you need.","Symptoms come after the dispatch request.","Assume the listener will act on your first sentence only."],"focus":["clarity","impact"],"placeholder":"Line 3 is down, hydraulic leak at the press — I need a tech now."},
    {"id":"lead-mfg-mid-03","level":"mid","profession":"industrial","title":"The tier-meeting update that meanders","scenario":"At the morning tier meeting you get 60 seconds. Yesterday you hit plan, but a bearing on the palletizer is running hot and could stop the line today. You tend to recap the whole shift chronologically.","task":"Write a 2-sentence tier update that leads with today's risk.","tips":["Lead with what could stop production today.","Yesterday's good news takes one clause, not one minute.","Name the help you need, if any."],"focus":["structure","concision"]},
    {"id":"lead-mfg-mid-04","level":"mid","profession":"industrial","title":"The handover text with the buried machine issue","scenario":"You're texting the incoming supervisor before you leave. The critical fact: the labeler is running only because of a temporary clamp fix that must be watched. Your draft starts with routine notes about staffing and cleanup.","task":"Write a handover text that puts the labeler warning first.","tips":["First line: the one thing that can bite them tonight.","Routine items follow, in one short list.","Tell them exactly what to watch and who to call."],"focus":["clarity","precision"],"placeholder":"Watch the labeler — it's running on a temporary clamp fix."},
    {"id":"lead-mfg-mid-05","level":"mid","profession":"industrial","title":"The quality-hold notice that eases in","scenario":"You just put 1,200 units on hold because torque readings drifted out of spec after 2 p.m. Your email to quality and the plant manager opens with background on the torque tool calibration schedule.","task":"Write a 2-3 sentence hold notice that leads with what is held and why.","tips":["Sentence one: quantity held, product, and the spec issue.","Calibration history is supporting detail.","State the immediate next step: containment and disposition."],"focus":["clarity","structure"],"placeholder":"I've placed 1,200 units of SKU 4417 on hold — torque drifted out of spec after 2 p.m."},
    {"id":"lead-mfg-mid-06","level":"mid","profession":"industrial","title":"The overtime ask that circles the runway","scenario":"You need the plant manager to approve eight hours of Saturday overtime for four operators to recover this week's shortfall. Your draft explains the week's downtime history for two paragraphs before making the request.","task":"Write a message that puts the approval request and cost in the first sentence.","tips":["Lead with the ask: hours, people, day, and rough cost.","The shortfall it recovers is your one-line justification.","Make yes/no easy — give a decision deadline."],"focus":["clarity","impact"],"placeholder":"Requesting approval for 8 hours Saturday OT, four operators (~$1,900), to recover the 300-unit shortfall."},
    {"id":"lead-mfg-mid-07","level":"mid","profession":"industrial","title":"The parts-shortage escalation","scenario":"Purchasing needs to expedite a gearbox or Line 2 stops Thursday. Your email to the purchasing lead starts with the story of how the old gearbox failed and what maintenance found.","task":"Write a 2-sentence escalation that leads with the deadline and the ask.","tips":["First sentence: what you need, by when, or the line stops.","Failure history is one supporting clause.","Copy the plant manager only if the ask is truly stuck."],"focus":["impact","concision"]},
    {"id":"lead-mfg-mid-08","level":"mid","profession":"industrial","title":"The downtime report opening","scenario":"You're writing the weekly downtime report. The headline is that changeovers, not breakdowns, drove 60% of lost time. Your draft opens with a table of every stoppage in chronological order.","task":"Write the report's opening line so the main finding comes first.","tips":["Lead with the single insight the data supports.","The stoppage log is the appendix, not the opening.","Make the reader's next question 'what do we do about changeovers?'"],"focus":["structure","precision"],"placeholder":"Changeovers, not breakdowns, drove 60% of last week's lost time."},
    {"id":"lead-mfg-mid-09","level":"mid","profession":"industrial","title":"The ship-date answer they asked for","scenario":"The plant manager asks in the hallway whether order 8802 ships Friday. It will, as long as tonight's sterilization run passes. You tend to walk through the whole routing before answering.","task":"Say a 1-2 sentence answer that gives the verdict first, then the condition.","tips":["Answer yes/no in the first breath.","Attach the one condition that matters.","Skip the routing narrative entirely."],"focus":["clarity","concision"],"placeholder":"Yes, Friday — as long as tonight's sterilization run passes."},
    {"id":"lead-mfg-mid-10","level":"mid","profession":"industrial","title":"The near-miss report that hides the event","scenario":"A pallet slid off a rack and landed a metre from an operator. No one was hurt. Your incident write-up opens with the warehouse layout and racking history before describing what happened.","task":"Write an opening 1-2 sentences that state the near-miss and its severity first.","tips":["Sentence one: what almost happened and to whom.","Layout and history are contributing factors — put them after.","Severity framing drives how fast people act."],"focus":["clarity","impact"]},
    {"id":"lead-mfg-mid-11","level":"mid","profession":"industrial","title":"The maintenance-window request","scenario":"You want maintenance to take Line 1 down for four hours Sunday to replace the worn conveyor belt before it fails mid-week. Your draft to the maintenance planner starts with the belt's inspection history.","task":"Write a 2-sentence request that leads with the window you want and why now.","tips":["Lead with the ask: which line, how long, which day.","'Before it fails mid-week' is the urgency — say it early.","Offer the schedule trade you've already cleared."],"focus":["clarity","structure"],"placeholder":"Requesting Line 1 down for 4 hours Sunday to replace the conveyor belt before it fails in-week."},
    {"id":"lead-mfg-mid-12","level":"mid","profession":"industrial","title":"The scrap-spike alert","scenario":"Scrap on the molding line tripled in the last two hours — something changed after the resin lot switch. Your message to quality walks through your whole troubleshooting sequence before naming the spike.","task":"Write an alert that leads with the spike and your best suspect.","tips":["First line: the number and when it started.","Your suspect (the resin lot) is the second sentence.","What you've ruled out goes last, briefly."],"focus":["precision","impact"],"placeholder":"Molding scrap tripled since 1 p.m. — the resin lot switch is my prime suspect."},
    {"id":"lead-mfg-mid-13","level":"mid","profession":"industrial","title":"The changeover-delay heads-up","scenario":"The changeover to the export SKU is running 90 minutes long because a die needed unexpected cleaning. Planning needs to know now so they can resequence. Your draft apologizes and explains before giving the delay.","task":"Write a 1-2 sentence heads-up to the planner that leads with the delay.","tips":["Lead with the number: 90 minutes late, new start time.","The die cleaning is one clause of context.","Give the planner what they need to act: the revised start."],"focus":["clarity","concision"],"placeholder":"Changeover is running 90 minutes long — new start for the export SKU is 3:30."},
    {"id":"lead-mfg-mid-14","level":"mid","profession":"industrial","title":"The recommendation you already made","scenario":"Maintenance offered two fixes for the recurring wrapper fault: a $400 sensor swap today or a $6,000 drive replacement at next shutdown. You've decided the sensor swap is right for now, but your email lays out both options neutrally for three paragraphs.","task":"Rewrite the opening so your recommendation comes first, with the trade-off after.","tips":["State your pick and its cost in sentence one.","Then the one reason, then the alternative you rejected.","A clear recommendation invites a faster yes."],"focus":["structure","impact"],"placeholder":"Recommend the $400 sensor swap today; the drive replacement can wait for shutdown."},
    {"id":"lead-mfg-mid-15","level":"mid","profession":"industrial","title":"The stop-the-line call","scenario":"You believe Line 4 should stop now: the seamer is producing intermittent bad seals, and every hour of running adds rework risk. Your message to the plant manager builds the case slowly, saving the recommendation for the end.","task":"Write a 2-3 sentence message that opens with the recommendation to stop.","tips":["Lead with the call: stop Line 4 now.","One sentence of evidence: intermittent bad seals, rework risk per hour.","Name the restart condition so it doesn't read as open-ended."],"focus":["impact","clarity"]},
    {"id":"lead-mfg-mid-16","level":"mid","profession":"industrial","title":"The new-hire progress note","scenario":"Your manager asked how the two new operators are doing after week one. The headline: one is ready for solo work, the other needs another week shadowing. Your draft describes each day of training before giving verdicts.","task":"Write a 2-sentence update that leads with both verdicts.","tips":["Verdicts first: ready / not yet, with the timeline.","Training details only if they change a decision.","Name what you need, if anything, to close the gap."],"focus":["concision","clarity"],"placeholder":"Dana is ready for solo work; Marcus needs one more week shadowing on changeovers."},
    {"id":"lead-mfg-mid-17","level":"mid","profession":"industrial","title":"The resequencing request","scenario":"You want the scheduler to move the short-run SKU ahead of the long run tomorrow so the crew can do the tricky changeover while your best setup tech is on shift. Your draft opens with staffing philosophy.","task":"Write a 2-sentence request that leads with the specific schedule change.","tips":["Lead with the swap: run X before Y tomorrow.","The setup-tech reason is your one-line justification.","Confirm nothing downstream slips — answer that objection early."],"focus":["clarity","structure"]},
    {"id":"lead-mfg-mid-18","level":"mid","profession":"industrial","title":"The trial-run recap","scenario":"Yesterday's trial of the new gasket supplier ran clean: zero leaks in 500 units, cycle time unchanged. Your email to engineering and purchasing starts with the trial setup and conditions before the result.","task":"Write an opening line that leads with the result.","tips":["Result first: zero leaks in 500, cycle time flat.","Setup and conditions are the supporting section.","Say what you recommend happen next."],"focus":["precision","impact"],"placeholder":"The gasket trial passed — zero leaks in 500 units, cycle time unchanged."},
    {"id":"lead-mfg-mid-19","level":"mid","profession":"industrial","title":"The receiving discrepancy","scenario":"The steel coil delivered this morning is 2mm gauge, not the 1.5mm on the PO — you can't run tomorrow's job with it. Your message to the materials manager recounts the unloading and inspection before stating the mismatch.","task":"Write a 2-sentence message that leads with the mismatch and the production impact.","tips":["First sentence: wrong spec received, which job it blocks.","Ask for the fix: correct coil by when.","Paperwork details go in the attachment, not the lede."],"focus":["clarity","precision"],"placeholder":"This morning's coil is 2mm, not the 1.5mm on the PO — tomorrow's bracket job can't run on it."},
    {"id":"lead-mfg-mid-20","level":"mid","profession":"industrial","title":"The toolbox-talk opening","scenario":"Today's toolbox talk is about the finger laceration on B shift last week. You want the crew's attention in the first ten seconds, but your usual opening is housekeeping announcements.","task":"Write the first two sentences of the talk, leading with why it matters today.","tips":["Open with the event and the lesson, not announcements.","Make it about this crew, this equipment, this week.","One clear behavior you're asking for by the end."],"focus":["impact","audience"]},
    {"id":"lead-mfg-mid-21","level":"mid","profession":"industrial","title":"The help request to engineering","scenario":"You need the process engineer to look at why the oven's zone 2 keeps drifting 10 degrees — today if possible, because you're running heat-sensitive product tomorrow. Your draft is a long description of every temperature log entry.","task":"Write a message that leads with the ask and the deadline.","tips":["Lead with: need you on the oven today, here's why it can't wait.","One line of symptom, not the whole log.","Attach the data instead of narrating it."],"focus":["clarity","concision"],"placeholder":"Can you look at oven zone 2 today? It's drifting 10 degrees and tomorrow's run is heat-sensitive."},
    {"id":"lead-mfg-mid-22","level":"mid","profession":"industrial","title":"The weekly KPI email","scenario":"Your weekly summary to the plant manager covers output, scrap, safety, and downtime. The story this week: output up 6%, everything else steady. Your draft gives all four metrics equal, chronological billing.","task":"Write an opening line that leads with the week's one headline.","tips":["Lead with the change, not the dashboard.","Steady metrics can share one sentence.","Say what drove the 6% so it can be repeated."],"focus":["structure","concision"],"placeholder":"Output up 6% this week — the new changeover sequence is holding."},
    {"id":"lead-mfg-mid-23","level":"mid","profession":"industrial","title":"The customer-complaint notification","scenario":"Quality traced a customer complaint about loose fasteners to a torque gun on your line that lost calibration for two days last month. You must tell the plant manager before the 2 p.m. quality review. Your draft opens defensively with everything your shift does right.","task":"Write a 2-3 sentence notification that leads with the finding.","tips":["Lead with the fact: complaint traced to our torque gun, two-day window.","Defensiveness delays the point and reads worse.","Close with containment: what's checked, what's changed."],"focus":["clarity","impact"]},
    {"id":"lead-mfg-mid-24","level":"mid","profession":"industrial","title":"The capital-request opening","scenario":"You're drafting the justification for a $28,000 automatic palletizer gate. The punchline: it pays back in 14 months from reduced manual handling and two fewer injuries a year. Your draft opens with the history of the manual process.","task":"Write the first two sentences of the justification, leading with the payback.","tips":["Lead with cost, payback period, and the safety gain.","History of the manual process is background.","Numbers in the first sentence earn the read."],"focus":["impact","precision"],"placeholder":"The $28,000 palletizer gate pays back in 14 months and removes our two most common lifting injuries."},
    {"id":"lead-mfg-mid-25","level":"mid","profession":"industrial","title":"The end-of-shift log entry","scenario":"The next supervisor reads your log entry standing up, in about 20 seconds. Tonight's essentials: plan hit, one hydraulic top-up on the press, and QC needs the 6 a.m. first-off sample early. Your entries usually run ten unranked lines.","task":"Write a 3-line log entry with the most important line first.","tips":["Rank lines by what the reader must act on.","The QC sample request is an action — put it on top.","'Plan hit' can be two words."],"focus":["structure","concision"],"placeholder":"1) QC needs the 6 a.m. first-off sample pulled EARLY —"}
  ],
  "start-with-the-audience": [
    {"id":"audience-mfg-mid-01","level":"mid","profession":"industrial","title":"OEE drop, translated for the plant manager","scenario":"OEE on Line 2 fell from 78% to 71%. You know it's availability, driven by micro-stops on the case packer. The plant manager doesn't want the OEE math — they want to know what it costs and what you're doing.","task":"Write a 2-3 sentence explanation framed around output and action, not the metric.","tips":["Translate 7 points of OEE into units or hours lost.","Name the cause in plain words: the case packer keeps stopping for seconds at a time.","End with your fix and when they'll see the number recover."],"focus":["audience","clarity"],"placeholder":"Line 2 lost about 400 units last week to short stops on the case packer."},
    {"id":"audience-mfg-mid-02","level":"mid","profession":"industrial","title":"The spec change, explained to operators","scenario":"Engineering tightened the fill-weight tolerance from ±3g to ±2g. The change notice is written in spec language. Your operators need to know what changes at their station, starting this shift.","task":"Write a 2-3 sentence huddle announcement that tells operators exactly what to do differently.","tips":["Lead with the behavior change, not the document number.","Say what the tighter band means at the scale they watch.","Tell them what to do when a reading is borderline."],"focus":["audience","clarity"],"placeholder":"Starting today, fill weight has to land within 2 grams, not 3 — here's what that means at your station."},
    {"id":"audience-mfg-mid-03","level":"mid","profession":"industrial","title":"Maintenance jargon for the planner","scenario":"Maintenance told you the press needs 'a ram guide rebuild, roughly a 12-hour job, waiting on ways liners.' The production planner needs to reschedule around it but doesn't speak maintenance.","task":"Rewrite the message for the planner in 2 sentences: what's unavailable, for how long, from when.","tips":["The planner needs machine, duration, and earliest start — nothing else.","Translate 'waiting on ways liners' into a date dependency.","Offer the constraint, not the mechanics."],"focus":["audience","precision"]},
    {"id":"audience-mfg-mid-04","level":"mid","profession":"industrial","title":"The quality hold, explained to customer service","scenario":"You put a batch on hold for a seal-strength check. Customer service is fielding a call from the customer expecting that batch Friday. They need something accurate they can say without overpromising.","task":"Write a 2-3 sentence note giving customer service what they can tell the customer.","tips":["Give them the safe sentence: what happened, what's being verified, when they'll know.","No internal jargon — 'hold' needs one plain-language gloss.","Separate what they may say from what's internal only."],"focus":["audience","clarity"],"placeholder":"You can tell the customer: we're running an extra quality check on their batch and will confirm ship date by Wednesday noon."},
    {"id":"audience-mfg-mid-05","level":"mid","profession":"industrial","title":"Lockout-tagout for day-one new hires","scenario":"You're giving the lockout-tagout portion of new-hire orientation. Your usual talk assumes people know what an energy source is. These four hires have never worked in a plant.","task":"Write the first 3-4 sentences of the talk for a true beginner.","tips":["Start from the danger, not the procedure name.","Define every term the moment you use it.","One vivid, concrete consequence beats a list of rules."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-mid-06","level":"mid","profession":"industrial","title":"The schedule change that affects the crew","scenario":"Planning moved the long run to Thursday, which means the crew's easy Friday is now a triple changeover. The scheduler's email explains the customer logic. Your crew cares what their week now looks like.","task":"Write a 2-3 sentence announcement framed around what changes for the crew.","tips":["Lead with their week: Friday is now the heavy day.","Give the reason in one line — crews accept changes they understand.","Say what you've done to make it manageable."],"focus":["audience","impact"]},
    {"id":"audience-mfg-mid-07","level":"mid","profession":"industrial","title":"Scrap cost for the finance partner","scenario":"The site accountant asked why material variance is up this month. The answer is the resin quality issue that drove three days of high scrap. They think in dollars and variances, not reject rates.","task":"Write a 2-3 sentence explanation in the accountant's terms.","tips":["Convert scrap percentage into dollars and the variance line it hits.","Give the time window so they can match it to their numbers.","Say whether it's resolved — they need to know if it recurs next month."],"focus":["audience","precision"],"placeholder":"About $11,000 of the variance is the bad resin lot we ran June 9-11."},
    {"id":"audience-mfg-mid-08","level":"mid","profession":"industrial","title":"Handover to a supervisor from another area","scenario":"A supervisor from packaging is covering your machining area tonight. Your usual handover assumes the reader knows which machine is which and the quirks of the Mazak. Tonight's reader knows none of it.","task":"Write a 3-4 sentence handover that a first-time visitor to your area can act on.","tips":["Spell out what your regular counterpart would already know.","Name machines by location, not nickname.","Give one 'if X happens, call Y' rule for the likeliest problem."],"focus":["audience","structure"]},
    {"id":"audience-mfg-mid-09","level":"mid","profession":"industrial","title":"The headcount case, in HR's language","scenario":"You need a requisition for one more operator. Your instinct is to talk about cycle times and coverage gaps. HR's questions are: what's the business impact, is it permanent, and what happens without it.","task":"Write a 2-3 sentence justification answering HR's actual questions.","tips":["Lead with the consequence of not filling it: overtime cost, fatigue, missed plan.","Say permanent or seasonal explicitly.","Cycle-time math goes in the attachment, not the ask."],"focus":["audience","impact"]},
    {"id":"audience-mfg-mid-10","level":"mid","profession":"industrial","title":"Downtime cause for a non-technical manager","scenario":"The plant manager, who came up through logistics, asks why Line 1 was down four hours. The real answer involves a servo drive fault code and an encoder replacement. They need the decision-relevant version.","task":"Write a 2-sentence explanation with no technical terms the manager wouldn't use.","tips":["Name the part by what it does, not its part number.","What they care about: is it fixed, will it recur, what does prevention cost.","Keep one technical noun at most, and gloss it."],"focus":["audience","clarity"],"placeholder":"The motor controller that positions the cutter failed; it's replaced, and I'm quoting a spare so a repeat costs us minutes, not hours."},
    {"id":"audience-mfg-mid-11","level":"mid","profession":"industrial","title":"Staging instructions for the warehouse","scenario":"Tomorrow's schedule needs raw material staged in run order, not delivery order — the crew loses 20 minutes every time a pallet is buried. The warehouse team doesn't see your schedule; they see pick lists.","task":"Write a 2-3 sentence request in terms of what the warehouse team should do differently.","tips":["Frame it as their workflow: stage in this sequence, this location.","Explain the 20-minute cost so it's a reason, not a whim.","Attach the run order rather than describing it."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-mid-12","level":"mid","profession":"industrial","title":"The control chart, explained at the line","scenario":"The SPC chart on the diameter check is trending toward the upper limit — not out of spec yet, but drifting. Operators see the chart but many treat it as wallpaper. You want them to act on the trend.","task":"Write a 2-3 sentence huddle explanation of what the chart is saying and what to do.","tips":["Translate the trend: the process is walking toward the edge, not over it yet.","Give the action: measure every 30 minutes, flag me at the warning line.","Skip SPC vocabulary — describe what they'd see and do."],"focus":["audience","precision"],"placeholder":"The diameters are creeping up — still in spec, but walking toward the limit."},
    {"id":"audience-mfg-mid-13","level":"mid","profession":"industrial","title":"The training step you always skip","scenario":"You're writing the changeover training sheet for new hires. Step 4 says 'set the guide rails' — obvious to you after ten years, meaningless to someone who's never seen the machine open.","task":"Rewrite the step in 2-3 sentences a first-week hire can follow without asking.","tips":["Write for the person who doesn't know which part is the guide rail.","Include the check: how they know they did it right.","Name the mistake beginners make and how to avoid it."],"focus":["audience","precision"]},
    {"id":"audience-mfg-mid-14","level":"mid","profession":"industrial","title":"The andon walkthrough for corporate visitors","scenario":"A corporate finance group is touring the floor. You have 30 seconds at the andon board. They don't know the system; they do care whether problems get fixed fast and what it saves.","task":"Write a 2-3 sentence explanation of the andon board pitched to that audience.","tips":["Lead with what it does for them: problems surface in minutes, not at month-end.","One concrete example: last week's save.","No lean vocabulary without an instant translation."],"focus":["audience","impact"]},
    {"id":"audience-mfg-mid-15","level":"mid","profession":"industrial","title":"One decision, two audiences","scenario":"You decided to rework 800 units rather than scrap them. The quality engineer needs the technical basis; the crew doing the rework needs what to do and why it's worth doing. You have to write both messages.","task":"Write the 2-sentence crew version of the rework decision.","tips":["The crew's stake: what the work is, how long, why it beats scrapping.","Keep the disposition logic for the quality engineer's version.","Respect their time: rework feels like punishment unless you frame the save."],"focus":["audience","clarity"],"placeholder":"We're reworking these 800 rather than scrapping them — about 3 hours of work saves the full batch."},
    {"id":"audience-mfg-mid-16","level":"mid","profession":"industrial","title":"'The press is down' — for scheduling","scenario":"The 400-ton press is down and maintenance says 'probably back by tomorrow afternoon.' The scheduler doesn't care about the press — they care which orders move and what to tell order management.","task":"Write a 2-3 sentence note to the scheduler in order terms, not machine terms.","tips":["Lead with the orders affected and the earliest they can run.","Convert 'probably tomorrow afternoon' into a planning assumption with a check-in time.","Offer the alternative you've already thought of (another press, resequence)."],"focus":["audience","structure"]},
    {"id":"audience-mfg-mid-17","level":"mid","profession":"industrial","title":"The PM window, sold to sales","scenario":"The annual maintenance shutdown takes capacity offline for five days in August. Sales is pushing back because it hits their quarter-end push. They hear 'maintenance' as 'optional.'","task":"Write a 2-3 sentence explanation of the shutdown in terms sales cares about.","tips":["Frame the trade: five planned days now versus unplanned weeks later.","Use a delivery consequence, not a maintenance argument.","Give them what to tell customers: exact dates, order-by cutoffs."],"focus":["audience","impact"],"placeholder":"Five planned days in August protects every delivery date in Q4 — here's the order-by cutoff to give your customers."},
    {"id":"audience-mfg-mid-18","level":"mid","profession":"industrial","title":"The 5S audit result, without the score-speak","scenario":"Your area scored 3.2 out of 5 on the 5S audit, dinged on tool shadowboards and staged WIP. Reading scores at the crew makes eyes glaze. They respond to what changes and who owns it.","task":"Write a 2-3 sentence huddle message that turns the audit into two concrete actions.","tips":["Skip the score; lead with the two findings in plain words.","Assign each action a name and a day.","Say what a pass looks like next month."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-mid-19","level":"mid","profession":"industrial","title":"Machine limits for the product engineer","scenario":"A product engineer designed a part with a bend radius your brake press can't hold consistently. They know CAD, not your equipment. You need them to change the design, not defend the machine.","task":"Write a 2-3 sentence message that frames the limit in terms of their part's quality.","tips":["Lead with what happens to their part: inconsistent radius, cracking risk.","Give the number the design needs to hit for reliable production.","Offer the meeting: 15 minutes at the press is worth ten emails."],"focus":["audience","precision"]},
    {"id":"audience-mfg-mid-20","level":"mid","profession":"industrial","title":"The late shipment, for the customer-facing team","scenario":"Order 5561 will ship Monday instead of Friday because of the extruder rebuild. The account manager needs to call the customer in an hour. Your first draft explains the rebuild in detail.","task":"Write a 2-3 sentence brief the account manager can use on the call.","tips":["What they need: new date, one-line reason, and whether it's firm.","Translate the rebuild into 'planned equipment repair that protects future orders.'","Flag anything they should NOT commit to."],"focus":["audience","clarity"],"placeholder":"Order 5561 ships Monday, not Friday — firm date."},
    {"id":"audience-mfg-mid-21","level":"mid","profession":"industrial","title":"The new PPE rule, announced right","scenario":"Cut-resistant gloves are now mandatory at the trim station after two lacerations in the region. The corporate bulletin is three pages. Your crew will hear it as another rule unless you frame why.","task":"Write a 2-3 sentence announcement that leads with the reason in crew terms.","tips":["Lead with the two lacerations, not the policy number.","State the rule in one sentence: where, when, no exceptions.","Tell them where the gloves are and who to see about sizing."],"focus":["audience","impact"]},
    {"id":"audience-mfg-mid-22","level":"mid","profession":"industrial","title":"Explaining temps to the permanent crew","scenario":"Six temporary workers start Monday for the seasonal peak. Rumors are already circulating that permanent jobs are at risk. Your crew needs the facts before the rumor hardens.","task":"Write a 2-3 sentence huddle message addressing what the crew is actually worried about.","tips":["Answer the unasked question first: no permanent positions are affected.","Say what the temps will and won't do.","Name who the crew should bring concerns to — you."],"focus":["audience","clarity"]},
    {"id":"audience-mfg-mid-23","level":"mid","profession":"industrial","title":"The automation pilot, for a worried crew","scenario":"A collaborative robot is being piloted on the packing station next month. The crew's first question won't be about the technology — it will be about their jobs. Your announcement has to meet that question head-on.","task":"Write a 3-4 sentence announcement that addresses job impact before describing the pilot.","tips":["Say what happens to jobs first, plainly and honestly.","Then what the robot does and what people move to.","Invite questions in a named forum, not just 'come see me.'"],"focus":["audience","impact"],"placeholder":"No one loses their job over this pilot — here's what actually changes."},
    {"id":"audience-mfg-mid-24","level":"mid","profession":"industrial","title":"The MES glitch, reported so IT can act","scenario":"The production-recording terminal keeps freezing at shift change, so counts post late and the morning report looks wrong. Your ticket draft says 'the system is broken again.' IT can't act on that.","task":"Rewrite the ticket in 2-3 sentences with what IT needs to reproduce and prioritize it.","tips":["Give when, where, and what exactly happens on screen.","State the business impact: morning report shows wrong counts.","Say what you've tried (restart) so they skip step one."],"focus":["audience","precision"]},
    {"id":"audience-mfg-mid-25","level":"mid","profession":"industrial","title":"The takt change, for team leads","scenario":"Customer demand rose, so the line's takt time drops from 52 to 47 seconds Monday. Your team leads have to rebalance stations. They need the practical consequence, not the demand math.","task":"Write a 2-3 sentence brief for team leads focused on what they must rebalance.","tips":["Lead with the operational fact: five fewer seconds per unit at every station.","Name the stations that won't make it without rebalancing.","Give them the deadline and the forum for working it: Friday's rebalance session."],"focus":["audience","structure"]}
  ],
  "structure-that-carries": [
    {"id":"structure-mfg-mid-01","level":"mid","profession":"industrial","title":"Eight downtime causes, three buckets","scenario":"Last week's downtime log lists eight causes: two jam types, a sensor fault, two changeover overruns, a material wait, an operator error, and a power dip. Your report to the plant manager can't be an eight-item list.","task":"Group the eight causes into 2-3 named buckets and write the one-sentence headline they support.","tips":["Group by what fixes them: equipment, changeover, supply.","The headline is the governing idea, not a category list.","A reader should predict your recommendations from the buckets alone."],"focus":["structure","clarity"],"placeholder":"Three things drove last week's downtime: equipment faults, changeover overruns, and material waits."},
    {"id":"structure-mfg-mid-02","level":"mid","profession":"industrial","title":"SCQA for the maintenance window","scenario":"You're proposing a standing four-hour maintenance window every second Sunday. Your draft dives straight into the proposed schedule. The plant manager needs the situation and the tension first, or the ask sounds like lost capacity.","task":"Write the proposal opening as SCQA in 4 sentences: situation, complication, question, answer.","tips":["Situation: breakdowns currently interrupt production unpredictably.","Complication: last quarter's unplanned stops cost more than any planned window would.","The answer is your window — stated as the resolution, not a wish."],"focus":["structure","impact"]},
    {"id":"structure-mfg-mid-03","level":"mid","profession":"industrial","title":"PREP in the production meeting","scenario":"In the daily production meeting you're asked whether the new SKU can move to Line 2 permanently. You have a view: yes, after the guarding modification. Unstructured, your answer will wander through everything you know about Line 2.","task":"Write your spoken answer in PREP form: point, reason, example, point — 4 sentences.","tips":["Point first: yes, with one condition.","One reason, one concrete example from the trial run.","Restate the point with the condition as the close."],"focus":["structure","clarity"],"placeholder":"Yes — Line 2 can take the new SKU permanently once the guarding mod is done."},
    {"id":"structure-mfg-mid-04","level":"mid","profession":"industrial","title":"The handover note that carries itself","scenario":"Your handover notes are a stream of consciousness: machine states, staffing, QC items, and reminders all interleaved in the order you thought of them. The night supervisor keeps missing items buried mid-paragraph.","task":"Design the 3-4 section structure for your standing handover note and write the one-line heading for each.","tips":["Order sections by urgency: act tonight, watch, FYI.","Same structure every day — readers navigate by habit.","Anything requiring action gets a name and a time."],"focus":["structure","audience"]},
    {"id":"structure-mfg-mid-05","level":"mid","profession":"industrial","title":"The corrective-action story in order","scenario":"Your corrective-action report for the label mix-up currently reads like a diary of the investigation. Quality needs it in the standard logic: what happened, why, what fixes it, how we prevent recurrence.","task":"Write the four section-opening sentences of the report, one per section.","tips":["Each opening sentence should stand alone as the section's summary.","Keep investigation chronology out of the 'why' — give the root cause, not the search.","Prevention must answer 'why can't this happen again', not 'we told everyone.'"],"focus":["structure","precision"]},
    {"id":"structure-mfg-mid-06","level":"mid","profession":"industrial","title":"Grouping the crew's complaints","scenario":"In the last month operators have raised: broken fans, a slippery dock, missing torque wrenches, stale training docs, unclear rework criteria, and a scheduling app nobody can read. You're bringing these to the plant manager and can't present a grab bag.","task":"Sort the six complaints into 2-3 themes and write the sentence introducing them.","tips":["Group by owner or by type: environment, tools and systems, standards.","Name each theme so it suggests its own fix.","The intro sentence tells the manager what the pile means, not what's in it."],"focus":["structure","clarity"],"placeholder":"The crew's issues come down to three things: the workspace, the tools, and unclear standards."},
    {"id":"structure-mfg-mid-07","level":"mid","profession":"industrial","title":"One governing idea for the week","scenario":"Your weekly report covers output, a quality save, two near-misses, and a training milestone. Listed flat, it reads as noise. This week the thread is real: the crew caught problems before they escaped.","task":"Write the governing-idea sentence for the report and the 3 bullet headlines under it.","tips":["The governing idea makes the four items one story.","Each bullet should visibly support the idea, not just coexist with it.","If an item doesn't fit the idea, it goes in a final 'also' line."],"focus":["structure","impact"]},
    {"id":"structure-mfg-mid-08","level":"mid","profession":"industrial","title":"The three-point toolbox talk","scenario":"Your toolbox talk on forklift-pedestrian safety has nine things you could say. Nine points means zero retained. You need three, in an order that builds.","task":"Choose and write the 3 points of the talk as one sentence each, in order.","tips":["Three points max — cut the other six without mercy.","Order for retention: risk, rule, what to do when the rule is broken.","Each point should be repeatable by an operator at the end."],"focus":["structure","concision"]},
    {"id":"structure-mfg-mid-09","level":"mid","profession":"industrial","title":"The improvement pitch, pyramid first","scenario":"Your pitch for relocating the tool crib has twelve supporting facts: walk-time studies, downtime entries, operator quotes, a layout sketch. Your draft presents evidence first, conclusion last — the plant manager may never reach the point.","task":"Write the pitch's top line (the recommendation) and the 3 support headlines beneath it.","tips":["Recommendation on top; evidence hangs below it in labeled groups.","Each support headline is a claim, not a data description.","Twelve facts become exhibits under three claims."],"focus":["structure","impact"],"placeholder":"Move the tool crib to the line side: it recovers 40 minutes of walk time per shift."},
    {"id":"structure-mfg-mid-10","level":"mid","profession":"industrial","title":"The incident timeline untangled","scenario":"The bearing failure unfolded over three shifts, with warnings, a temporary fix, and the final stop. Your first draft mixes what happened, what people thought, and what should have happened. The reader needs the sequence clean before the analysis.","task":"Write a 4-5 line timeline of the incident, one event per line, facts only.","tips":["Timestamp every line; one event per line.","Strip opinions and hindsight from the timeline — they go in the analysis section.","The timeline should let a stranger reconstruct the incident unaided."],"focus":["structure","precision"]},
    {"id":"structure-mfg-mid-11","level":"mid","profession":"industrial","title":"The training outline that builds","scenario":"You're structuring the two-day onboarding for new packers. Your current list is fifteen topics in random order — safety wedged between quality paperwork and lunch logistics. Sequence matters: each block should assume only what came before.","task":"Write a 4-5 line outline with a one-line rationale for the order.","tips":["Order by dependency: safety before machine, machine before quality checks.","Group small topics into blocks with names.","State the rationale in one line so co-trainers keep the order."],"focus":["structure","audience"]},
    {"id":"structure-mfg-mid-12","level":"mid","profession":"industrial","title":"SCQA for the staffing request","scenario":"You want a fifth operator on nights. Bare, the ask sounds like padding. Framed, it's a response to a real complication: the fourth-quarter volume ramp is colliding with two upcoming retirements.","task":"Write the request as SCQA in 4 sentences.","tips":["Situation: current crew covers current volume.","Complication: volume ramps 20% while two retire — the math breaks in October.","Answer: hire in August so training finishes before the ramp."],"focus":["structure","impact"],"placeholder":"Nights runs fine today with four operators. But Q4 volume rises 20% just as two of them retire..."},
    {"id":"structure-mfg-mid-13","level":"mid","profession":"industrial","title":"Scrap causes, grouped for action","scenario":"The month's scrap Pareto shows eleven defect codes. Three trace to one worn die, four to operator setup variation, and the rest are noise. Your quality review slide currently shows all eleven bars and no message.","task":"Write the slide's headline sentence and the 2-3 groups you'd present.","tips":["Headline the concentration: two causes explain most of the scrap.","Group codes by root cause, not by defect appearance.","'Noise' is a legitimate third group — name it and move on."],"focus":["structure","precision"]},
    {"id":"structure-mfg-mid-14","level":"mid","profession":"industrial","title":"The cross-shift meeting agenda","scenario":"You're chairing the first alignment meeting between day and night shift after weeks of friction over handover quality. Without structure it becomes a complaint session. You have 30 minutes.","task":"Write a 3-4 item agenda with a time and an outcome for each item.","tips":["Each item names its outcome: a decision, a standard, an owner.","Put the emotional item (the friction) inside a structured slot, not first or last.","Reserve the last five minutes for actions and owners — always."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-mid-15","level":"mid","profession":"industrial","title":"PREP for 'why did we miss?'","scenario":"The ops director will ask you in the review why the week's plan was missed. The honest answer: one 6-hour breakdown, and the recovery plan worked — you recovered half the loss. Rambling here reads as excuse-making.","task":"Write your spoken PREP answer in 4 sentences.","tips":["Point: we missed by 200 units; one breakdown explains it.","Reason and example carry the evidence, including the recovery.","The closing point includes what prevents the repeat."],"focus":["structure","clarity"],"placeholder":"We missed plan by 200 units, and one event explains it: the six-hour gearbox failure on Tuesday."},
    {"id":"structure-mfg-mid-16","level":"mid","profession":"industrial","title":"The changeover SOP summary","scenario":"The full changeover SOP is nine pages. Your best setup tech does it from memory in a sequence that never fails: prepare, swap, verify. New techs read the nine pages and still get lost.","task":"Write a 3-heading summary structure for the SOP with 1-2 lines under each heading.","tips":["Three phases a tech can hold in their head.","Under each heading: what done looks like, not every step.","The summary points into the full SOP; it doesn't replace it."],"focus":["structure","concision"]},
    {"id":"structure-mfg-mid-17","level":"mid","profession":"industrial","title":"The hold email's one idea","scenario":"Your quality-hold email covers the defect, the affected lots, the customer exposure, the containment, and the disposition plan. Five topics, but one idea: the problem is contained and the exposure is known. Your draft has no top line saying so.","task":"Write the governing sentence and the 3-4 bullet labels that would follow it.","tips":["The top line answers the reader's fear: is this contained?","Bullets are labeled by topic so each stakeholder finds theirs.","Anything unknown goes in its own labeled bullet — hiding it breaks trust."],"focus":["structure","clarity"],"placeholder":"The seal defect is contained: all suspect lots are held on site and no product shipped."},
    {"id":"structure-mfg-mid-18","level":"mid","profession":"industrial","title":"The maintenance backlog, bucketed","scenario":"You and the maintenance planner are reviewing 23 open work orders on your lines. Read serially, the list produces no decisions. Grouped, it would: some are safety, some protect the schedule, some are comfort.","task":"Name 3 buckets for the backlog and write the one-line decision rule for each.","tips":["Buckets should imply their own priority order.","A decision rule says what happens to items in the bucket, and by when.","The grouping is for deciding, not for filing."],"focus":["structure","impact"]},
    {"id":"structure-mfg-mid-19","level":"mid","profession":"industrial","title":"SCQA for the fourth machine","scenario":"You believe the cell needs a fourth CNC machine. The capital committee reads dozens of requests framed as 'we want.' Yours should be framed as a situation that has stopped working.","task":"Write the justification's opening as SCQA in 4-5 sentences.","tips":["Situation: three machines met demand through last year.","Complication: demand grew 30%; overtime and weekend shifts now cap you out.","Question implied: how do we meet committed volume? Answer: the fourth machine, with payback."],"focus":["structure","impact"]},
    {"id":"structure-mfg-mid-20","level":"mid","profession":"industrial","title":"Three findings, three responses","scenario":"The customer audit produced three findings: incomplete training records, an uncalibrated gauge in use, and missing labels on WIP racks. Your response document must address each with the same discipline: finding, fix, prevention, date.","task":"Write the response to ONE finding using that four-part structure, one line per part.","tips":["Restate the finding in your own words — it proves you understood it.","Fix and prevention are different lines; auditors look for the difference.","Every line with an action gets a date and an owner."],"focus":["structure","precision"]},
    {"id":"structure-mfg-mid-21","level":"mid","profession":"industrial","title":"The handover checklist, ordered by risk","scenario":"You're formalizing the shift handover into a checklist. Your brainstorm produced 14 items in no order. The incoming supervisor will do this standing at the desk in five minutes — order and grouping decide whether it works.","task":"Organize the checklist into 3 groups and write the group headings plus the first item of each.","tips":["Group by the reader's question: what's running, what's broken, what's coming.","Highest-consequence items first within each group.","Fourteen items is too many — merging is part of structuring."],"focus":["structure","concision"]},
    {"id":"structure-mfg-mid-22","level":"mid","profession":"industrial","title":"The production-plan email skeleton","scenario":"Every Friday you send next week's plan to the crew leads, quality, and maintenance. Each audience reads for something different: the crew for shifts, quality for first-offs, maintenance for windows. Your current email is one long paragraph.","task":"Write the email's 3-4 section headings and the one-line summary that opens the email.","tips":["Open with the week in one sentence: volume, the one unusual thing.","Section per audience need, labeled so people can skip.","The unusual thing (trial run, new SKU) gets its own section, never buried."],"focus":["structure","audience"],"placeholder":"Next week: normal volume, one exception — Wednesday's trial run on Line 2."},
    {"id":"structure-mfg-mid-23","level":"mid","profession":"industrial","title":"PREP for the headcount question","scenario":"In the budget meeting someone will ask: 'Can't you run nights with four instead of five?' You can't, and you know exactly why — relief coverage and the two-person rule on the press. The answer needs shape, not volume.","task":"Write your spoken PREP answer in 4 sentences.","tips":["Point: no — four breaks the two-person press rule every break rotation.","Example: walk one break cycle to show the gap.","Close by restating the point plus the real alternative (automation, not thinner crews)."],"focus":["structure","clarity"]},
    {"id":"structure-mfg-mid-24","level":"mid","profession":"industrial","title":"Kaizen output into a plan","scenario":"The kaizen event generated 31 sticky notes of ideas for the packing area. As a flat list they'll die in a drawer. They sort naturally: do-now, needs-maintenance, needs-money.","task":"Write the report-out structure: 3 category names, each with a one-line definition and owner.","tips":["Categories by what unblocks them, not by theme.","Every category has an owner and a review date, or it's a wish list.","Lead the report-out with the do-nows — momentum is the point of kaizen."],"focus":["structure","impact"]},
    {"id":"structure-mfg-mid-25","level":"mid","profession":"industrial","title":"The escalation email, ask first","scenario":"Your escalation about the recurring chiller failure needs to reach the engineering manager, with history, cost, and two failed fix attempts as context. If the structure buries the ask, it becomes another FYI.","task":"Write the email skeleton: the one-sentence ask, then 3 labeled context sections in order.","tips":["The ask is the subject line and sentence one, restated nowhere else.","Context sections ordered by decision relevance: cost, failed fixes, history.","Each section is scannable in five seconds — labels do the work."],"focus":["structure","clarity"],"placeholder":"Ask: assign a controls engineer to the Line 3 chiller this week — third failure in six weeks."}
  ],
  "cut-to-the-bone": [
    {"id":"concise-mfg-mid-01","level":"mid","profession":"industrial","title":"The shift report, halved","scenario":"Your end-of-shift report runs 200 words: 'It should also be noted that we experienced some minor issues with respect to the labeling equipment...' The next reader skims it standing up. Everything in it can be said in half the words.","task":"Rewrite this sentence in under 10 words: 'It should be noted that we experienced intermittent issues with respect to the functionality of the labeling equipment throughout the duration of the shift.'","tips":["'It should be noted that' notes nothing — delete it.","'With respect to the functionality of' is 'with.'","Name the machine, name the problem, stop."],"focus":["concision","clarity"],"placeholder":"The labeler jammed intermittently all shift."},
    {"id":"concise-mfg-mid-02","level":"mid","profession":"industrial","title":"The hedged overtime request","scenario":"Your draft to the plant manager: 'I was wondering if it might possibly be feasible to perhaps consider approving some overtime this weekend, if that would be okay.' Four hedges deep, the request has disappeared.","task":"Rewrite the request in one direct sentence.","tips":["One polite ask needs zero hedges.","'I was wondering if it might' is 'please' or nothing.","Direct is not rude — vague is costly."],"focus":["concision","impact"],"placeholder":"Please approve eight hours of Saturday overtime for the packing crew."},
    {"id":"concise-mfg-mid-03","level":"mid","profession":"industrial","title":"The nominalized downtime summary","scenario":"Your report reads: 'The implementation of the repair was completed by maintenance, and the resumption of production occurred at 14:30.' Every action is buried inside a noun.","task":"Rewrite the sentence with verbs doing the work, in under 12 words.","tips":["'The implementation of the repair was completed' = 'maintenance repaired it.'","'The resumption of production occurred' = 'production resumed.'","Nouns hide actors; verbs name them."],"focus":["concision","clarity"],"placeholder":"Maintenance fixed the press; production resumed at 14:30."},
    {"id":"concise-mfg-mid-04","level":"mid","profession":"industrial","title":"The andon escalation script","scenario":"When operators call you to a stopped station, your radio reply is often thirty seconds of thinking out loud. The escalation script should be five seconds: acknowledge, instruction, ETA.","task":"Write a radio reply of 12 words or fewer for: an operator reports the capper jammed again.","tips":["Acknowledge in one word.","One instruction: what they do until you arrive.","Your ETA is the whole comfort — give it."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-mid-05","level":"mid","profession":"industrial","title":"The meta-commentary opener","scenario":"Your email to quality begins: 'I wanted to reach out to touch base regarding the topic of the recent increase we have been seeing in the area of rework.' Twenty-six words before content.","task":"Rewrite the opening sentence so it starts with the content.","tips":["'I wanted to reach out regarding' is a throat-clear — cut it.","Start with the fact: rework is up.","The reader learns nothing until the noun arrives — move it forward."],"focus":["concision","clarity"],"placeholder":"Rework on Line 2 doubled this month —"},
    {"id":"concise-mfg-mid-06","level":"mid","profession":"industrial","title":"The redundant-pair audit","scenario":"Your safety briefing draft says: 'each and every operator', 'full and complete lockout', 'first and foremost', 'basic and fundamental rules.' The pairs feel formal but say each thing twice.","task":"Rewrite this sentence keeping one word per pair: 'First and foremost, each and every operator must perform a full and complete lockout before any and all maintenance.'","tips":["Every pair here survives on one word.","Formality is not doubled words — it's precision.","Read it aloud after cutting; it gains authority."],"focus":["concision","precision"]},
    {"id":"concise-mfg-mid-07","level":"mid","profession":"industrial","title":"The wordy SOP step","scenario":"Step 7 of the cleaning SOP reads: 'At this point in the process, the operator should proceed to carry out the removal of the guard in order to gain access to the blade area for the purpose of cleaning.' Operators skim it and improvise.","task":"Rewrite the step as one instruction of 8 words or fewer.","tips":["Command form: verb first.","'For the purpose of' and 'in order to' rarely survive editing.","Instructions get followed in proportion to how fast they read."],"focus":["concision","clarity"],"placeholder":"Remove the guard and clean the blade area."},
    {"id":"concise-mfg-mid-08","level":"mid","profession":"industrial","title":"The apology that swallows the message","scenario":"You need to tell the planner a job will finish late. Your draft spends three sentences apologizing before the fact arrives. One apology, then the news, is the honest version.","task":"Rewrite as 2 sentences: the fact with the new time, and one clean apology.","tips":["Bad news gains nothing from a long wind-up.","One 'sorry' spends better than three.","The planner's next move needs the time, not the remorse."],"focus":["concision","impact"]},
    {"id":"concise-mfg-mid-09","level":"mid","profession":"industrial","title":"The huddle announcement, timed","scenario":"You have the crew's attention for 90 seconds at shift start. Your notes for today cover the schedule, one quality alert, and the parking-lot repaving. Written out, it's 250 words. Spoken, that's over two minutes of drift.","task":"Cut the announcement to 60 words covering all three items.","tips":["One sentence per item; the quality alert gets the strongest verb.","Parking lot is one clause, not a paragraph.","End on the item you want remembered."],"focus":["concision","structure"]},
    {"id":"concise-mfg-mid-10","level":"mid","profession":"industrial","title":"The double-speak downtime entry","scenario":"The log says: 'Line experienced a period of unplanned non-productive time due to the occurrence of an unexpected mechanical anomaly.' That's 'the line broke down' wearing a suit.","task":"Rewrite the entry in plain words, under 10 words, keeping the facts.","tips":["'Unplanned non-productive time' is downtime.","'Unexpected mechanical anomaly' is a breakdown — name the part if known.","Log entries are for finding facts fast, not for sounding official."],"focus":["concision","precision"],"placeholder":"Conveyor drive failed; line down 45 minutes."},
    {"id":"concise-mfg-mid-11","level":"mid","profession":"industrial","title":"The email that buries one question","scenario":"Your email to the quality manager asks one thing — can the retained samples be released — but wraps it in 150 words of batch history they already know. They will skim, miss the question, and not reply.","task":"Rewrite the email in 2 sentences: the question, then only the context needed to answer it.","tips":["The question is the email; everything else auditions for deletion.","Context they already know is zero-value weight.","A reply-able email fits on one phone screen."],"focus":["concision","clarity"],"placeholder":"Can we release the retained samples from batch 2214?"},
    {"id":"concise-mfg-mid-12","level":"mid","profession":"industrial","title":"The filler-word radio habit","scenario":"Listening to a recording of the shift channel, you hear yourself: 'um, basically, what we're kind of looking at is, you know, sort of a situation where the wrapper is acting up a little bit.' In an emergency this habit costs seconds.","task":"Rewrite that transmission as one clean sentence.","tips":["'Basically', 'kind of', 'sort of' subtract authority.","'A situation where X is acting up' = 'X is faulting.'","Radio discipline: fact, location, need."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-mid-13","level":"mid","profession":"industrial","title":"The 200-word maintenance request","scenario":"Your work-order note describes the whole history of the vibrating fan before asking for a bearing check. The tech will read the first line and the last. Everything that matters must live there.","task":"Rewrite the work order in 2 sentences: symptom with location, and what you want done.","tips":["Symptom, location, since when — one sentence.","The request is its own sentence, not implied.","History belongs in the CMMS record, not the request."],"focus":["concision","precision"],"placeholder":"Exhaust fan 4 (roof, east end) vibrating since Tuesday — check bearings this week."},
    {"id":"concise-mfg-mid-14","level":"mid","profession":"industrial","title":"The meeting invite with no meat","scenario":"Your calendar invite says: 'Meeting to discuss and align on various ongoing topics related to the line 2 situation.' Nobody can prepare for that, so nobody will.","task":"Rewrite the invite body in 2 sentences: the decision to be made and what to bring.","tips":["Name the decision, not the topic.","'Various ongoing topics' guarantees an unprepared room.","What to bring = who actually needs to attend."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-mid-15","level":"mid","profession":"industrial","title":"The safety-briefing sentence that sprawls","scenario":"Your briefing draft: 'It is important to be aware of the fact that, in the event that the light curtain is triggered, there is a possibility that the machine may enter a fault state which will require a reset.' The crew tunes out by word ten.","task":"Rewrite in under 15 words without losing the instruction.","tips":["'It is important to be aware of the fact that' is zero words of content.","'In the event that' = 'if.'","Say what happens and what to do — nothing else."],"focus":["concision","clarity"],"placeholder":"If the light curtain trips, the machine faults — reset it before restarting."},
    {"id":"concise-mfg-mid-16","level":"mid","profession":"industrial","title":"The paragraph that is one number","scenario":"Your update to the plant manager spends five sentences saying the changeover-reduction project is going well. The only content is one number: average changeover is down from 48 to 31 minutes.","task":"Rewrite the update as 1-2 sentences built around the number.","tips":["When you have a number, the number is the message.","'Going well' is a claim; 48-to-31 is proof.","Add only the next milestone."],"focus":["concision","precision"],"placeholder":"Changeovers are down from 48 to 31 minutes on average."},
    {"id":"concise-mfg-mid-17","level":"mid","profession":"industrial","title":"The 'as per my last email' chain","scenario":"You're writing the third follow-up about the missing guard rail part. Each follow-up has restated the whole saga, growing longer each time. The reader now faces a wall of text where a two-line nudge would land better.","task":"Write a follow-up of 2 sentences maximum that gets a response.","tips":["State the ask and the new deadline; link the history, don't retell it.","Add the consequence of continued silence — one clause.","Longer follow-ups read as venting, not urgency."],"focus":["concision","impact"]},
    {"id":"concise-mfg-mid-18","level":"mid","profession":"industrial","title":"The qualifier pile-up on quality","scenario":"Your note to the team: 'There may potentially be a possible issue with some of the units that could perhaps affect certain customers in some cases.' Five qualifiers deep, nobody will check anything.","task":"Rewrite with at most one honest qualifier, under 15 words.","tips":["Keep one 'may' if uncertainty is real — delete the rest.","Say which units and which defect, even approximately.","Vagueness reads as 'ignore this.'"],"focus":["concision","precision"],"placeholder":"Units from Tuesday's run may have weak welds — pull five and check."},
    {"id":"concise-mfg-mid-19","level":"mid","profession":"industrial","title":"The training doc introduction nobody reads","scenario":"The changeover guide opens with 180 words on the importance of following procedures, the history of the document, and who approved it. New techs skip to page two. The intro's only real job: what this covers and when to use it.","task":"Write a replacement introduction in 2 sentences.","tips":["Sentence one: what the document covers.","Sentence two: when to use it and where the full SOP lives.","Approval history goes in the footer."],"focus":["concision","audience"]},
    {"id":"concise-mfg-mid-20","level":"mid","profession":"industrial","title":"The incident-report padding","scenario":"Your near-miss report says: 'Due to the fact that the area in question was, at the time of the incident, in a condition that could be described as wet...' Safety reports get read under time pressure — padding hides facts investigators need.","task":"Rewrite the fragment as a plain factual sentence.","tips":["'Due to the fact that' = 'because.'","'The area in question was in a condition that could be described as wet' = 'the floor was wet.'","Plain facts speed the fix; formality delays it."],"focus":["concision","precision"],"placeholder":"The floor by the mixer was wet because the drain had backed up."},
    {"id":"concise-mfg-mid-21","level":"mid","profession":"industrial","title":"Two-minute update, thirty seconds given","scenario":"You prepared a two-minute update for the ops review, but the agenda is running long and the director says 'thirty seconds.' Your update covers the recovery plan, its cost, and the new risk. You must cut on your feet.","task":"Write the 30-second version in 2-3 sentences.","tips":["Keep the decision-relevant core: status, cost, the one risk.","Cut the narrative of how you got here.","Offer detail on request: 'happy to go deeper offline.'"],"focus":["concision","structure"]},
    {"id":"concise-mfg-mid-22","level":"mid","profession":"industrial","title":"The double-negative instruction","scenario":"The posted notice reads: 'Operators should not fail to verify that the interlock is not disengaged before proceeding.' Two negatives deep, half the crew reads it wrong.","task":"Rewrite the notice as a positive instruction, under 10 words.","tips":["Say what to do, not what not to fail to avoid.","Positive commands verify faster under pressure.","Test: would a tired operator at hour eleven parse it right?"],"focus":["concision","clarity"],"placeholder":"Check the interlock is engaged before starting."},
    {"id":"concise-mfg-mid-23","level":"mid","profession":"industrial","title":"The escalation with three asks","scenario":"Your email to the plant manager asks for overtime approval, a decision on the vendor quote, and sign-off on the training plan — buried in six paragraphs. Three asks in prose is how asks get lost.","task":"Rewrite as a 4-line email: one framing line and three one-line asks.","tips":["Number the asks; give each a deadline.","One line of framing is enough for all three.","If an ask needs a paragraph, it needs its own email."],"focus":["concision","structure"]},
    {"id":"concise-mfg-mid-24","level":"mid","profession":"industrial","title":"The handover voicemail","scenario":"The incoming supervisor is driving in and you're leaving early. You get one voicemail. Your instinct is to talk for three minutes; they'll retain fifteen seconds of it.","task":"Write a voicemail script of 40 words or fewer with tonight's two essentials.","tips":["Two items maximum — a voicemail is not a document.","Lead with the item that can hurt someone or stop the line.","End with where the full written handover is."],"focus":["concision","clarity"]},
    {"id":"concise-mfg-mid-25","level":"mid","profession":"industrial","title":"Half the words, same meaning","scenario":"Your paragraph for the monthly report: 'In the course of the month of May, the team was able to successfully achieve a reduction in the overall level of scrap that was being generated, bringing the rate down from 4.1% to 2.9%, which represents a significant improvement.' (48 words.)","task":"Rewrite it in 15 words or fewer without losing any fact.","tips":["'Was able to successfully achieve a reduction' = 'cut.'","The numbers carry 'significant' — delete the adjective.","Halving is a floor, not a ceiling."],"focus":["concision","precision"],"placeholder":"May scrap fell from 4.1% to 2.9%."}
  ],
  "precision-and-evidence": [
    {"id":"precision-mfg-mid-01","level":"mid","profession":"industrial","title":"Numbers for 'a lot of downtime'","scenario":"Your weekly report says Line 2 'had a lot of downtime and it really hurt output.' The plant manager can't act on 'a lot' — they need hours, the top cause, and the units it cost.","task":"Rewrite the sentence with the downtime hours, the leading cause, and the output impact in numbers.","tips":["Replace 'a lot' with the hours: 7.5 across the week.","'Really hurt output' becomes the unit shortfall.","Name the top cause so the number points at a fix."],"focus":["precision","clarity"],"placeholder":"Line 2 lost 7.5 hours last week — 60% to case-packer jams — costing about 1,100 units."},
    {"id":"precision-mfg-mid-02","level":"mid","profession":"industrial","title":"The scrap number with no So What","scenario":"Your monthly summary states 'scrap ran 3.4% in May' and moves on. The plant manager sees the number but not the meaning: whether it's good, what drives it, and what you're doing.","task":"Add the So What and Now What: the insight behind 3.4% and your next action, in two sentences.","tips":["Compare it: 3.4% against a 2.5% target is the story.","Name the driver — one SKU, one shift, one machine?","Now what: the single action that moves it most."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-03","level":"mid","profession":"industrial","title":"Date the belt replacement","scenario":"Asked when the worn conveyor belt gets replaced, your note says 'soon, once maintenance frees up a slot.' Planning is sequencing next week's runs around this and needs a date, not an intention.","task":"Rewrite committing to a specific date or a dated decision point.","tips":["Replace 'soon' with the day — or the day you'll have one.","'Once maintenance frees up' is a dependency; name when it resolves.","A date can be planned around; 'soon' gets ignored."],"focus":["precision","clarity"],"placeholder":"The belt swap is booked for Sunday the 14th; I'll confirm maintenance's slot by Thursday noon."},
    {"id":"precision-mfg-mid-04","level":"mid","profession":"industrial","title":"Skeptic test: 'changeovers are getting faster'","scenario":"You tell the ops review that changeovers 'are getting noticeably faster since the crew started pre-staging.' A skeptic asks: faster from what, to what, over how many changeovers? Your claim has no numbers behind it.","task":"Rewrite the claim so it survives a skeptical reading, with baseline, current figure, and sample.","tips":["State the before and after: 62 minutes down to 41.","Say how many changeovers the average covers.","Include the evidence a skeptic would demand before they ask."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-05","level":"mid","profession":"industrial","title":"Quantify 'the crew is stretched'","scenario":"Your overtime request says the shift is 'stretched thin covering the vacancies and it's not sustainable.' The plant manager approves numbers, not adjectives — they need the gap and what it costs.","task":"Rewrite with the specific staffing gap, the coverage cost, and the consequence they measure.","tips":["'Stretched thin' becomes: two certified press operators short on nights.","Show the cost: 14 OT hours a week to cover it.","Tie it to a metric they watch — missed changeovers or fatigue-driven errors."],"focus":["precision","impact"],"placeholder":"Nights is two certified press operators short; covering it costs 14 OT hours a week."},
    {"id":"precision-mfg-mid-06","level":"mid","profession":"industrial","title":"The forty-number downtime slide","scenario":"Your review slide is a table of every stoppage last month — forty rows, no takeaway. The room stares at it waiting for you to say what it means. The insight is in there: three faults cause most of it.","task":"Write the single insight sentence the table supports, to lead the slide.","tips":["Find the concentration: three faults drive 70% of lost time.","Lead with that sentence; the table becomes evidence.","If you can't name the insight, the data isn't ready to present."],"focus":["precision","structure"],"placeholder":"Three faults — packer jams, label splices, and die changes — drive 70% of our lost time."},
    {"id":"precision-mfg-mid-07","level":"mid","profession":"industrial","title":"Replace 'pretty reliable' with the numbers","scenario":"Asked how the new gasket supplier is performing, you say 'pretty reliable so far, no major issues.' Purchasing is deciding whether to move more volume to them and needs the reject rate and delivery record.","task":"Rewrite with the reject rate, on-time delivery figure, and the sample size behind both.","tips":["'Pretty reliable' becomes 0.2% rejects across six deliveries.","'No major issues' becomes the count of minor ones, named.","Numbers let purchasing decide; impressions make them re-ask."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-mid-08","level":"mid","profession":"industrial","title":"What, So What, Now What on the scrap spike","scenario":"Your note to quality says only 'molding scrap spiked Tuesday afternoon.' Missing: what it signals and what you're doing. Quality is left to interpret — or to escalate on your behalf.","task":"Rewrite as What, So What, Now What in three tight sentences.","tips":["What: scrap hit 6% Tuesday from 2%. So what: it tracks the new resin lot, not the machine.","Now what: the lot is quarantined and the old lot is running clean.","The three-part frame turns a spike into a handled event."],"focus":["precision","structure"],"placeholder":"Molding scrap hit 6% Tuesday, up from 2%. It tracks the new resin lot, not the machine."},
    {"id":"precision-mfg-mid-09","level":"mid","profession":"industrial","title":"Precise the safety claim","scenario":"Your safety update says near-misses are 'way down since the new walkway markings and the crew's really bought in.' The HSE manager wants counts, the rate, and the period — not enthusiasm.","task":"Rewrite with the near-miss count, the comparison period, and one measured behavior change.","tips":["'Way down' becomes two reports this quarter versus seven last.","Normalize if hours changed — a slow quarter flatters the count.","'Bought in' becomes something counted: walkway audits passed."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-10","level":"mid","profession":"industrial","title":"The vague complaint to the resin supplier","scenario":"Your escalation to the resin supplier says recent lots have been 'inconsistent and causing problems on our line.' Without specifics they'll ask for examples and the loop will drag for weeks.","task":"Rewrite with the lot numbers, the measured defect rate, and the dates.","tips":["'Inconsistent' becomes: lots 7741 and 7756, 6% scrap versus our 2% norm.","Name the failure mode — short shots, flash — with counts.","Dated, numbered claims get a corrective action; vague ones get a shrug."],"focus":["precision","clarity"],"placeholder":"Lots 7741 and 7756 ran 6% scrap against our 2% norm — short shots, logged June 12-16."},
    {"id":"precision-mfg-mid-11","level":"mid","profession":"industrial","title":"Cost the micro-stops","scenario":"You want the case-packer sensor upgrade approved and your draft argues the short stops are 'a constant drain and add up to a lot over time.' Finance weighs dollars against the $3,200 quote, not drains.","task":"Rewrite converting the micro-stops into a cost per week, with the components shown.","tips":["Count them: 40 stops a shift at 45 seconds each.","Convert to units, then dollars per week.","Put the cost next to the quote so the math closes itself."],"focus":["precision","impact"],"placeholder":"The short stops cost about 2.5 hours a week — roughly 360 units, or $2,900 — against a $3,200 one-time fix."},
    {"id":"precision-mfg-mid-12","level":"mid","profession":"industrial","title":"'Improving' with no baseline","scenario":"You tell the plant manager Line 4's OEE is 'trending in the right direction since the rebalance.' Without the start point, the current figure, and the window, they can't tell recovery from wishful reading.","task":"Rewrite with the baseline, the current number, and how many weeks of trend.","tips":["Name where it started and where it is now.","Say how many consecutive weeks — one good week isn't a trend.","Direction words earn trust only with numbers behind them."],"focus":["precision","clarity"],"placeholder":"Line 4 OEE has climbed from 68% to 74% over three consecutive weeks since the rebalance."},
    {"id":"precision-mfg-mid-13","level":"mid","profession":"industrial","title":"Quantify the changeover pilot","scenario":"Reporting the pre-staged tooling pilot, you say it 'made a real difference and the crew found it easier.' The plant manager needs the measured minutes saved and any quality effect before rolling it to all lines.","task":"Rewrite with the time reduction, the quality result, and the sample behind both.","tips":["'Real difference' becomes 21 minutes saved per changeover.","Report first-off pass rate too — speed that costs quality is no win.","Name the sample: 14 changeovers across two crews."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-14","level":"mid","profession":"industrial","title":"The skeptic on the palletizer payback","scenario":"Your $28,000 palletizer-gate request claims it 'pays for itself quickly through fewer injuries and less manual handling.' A skeptical reviewer asks: what savings, over what period, and what if volume drops?","task":"Rewrite with the payback period, the named savings sources, and the volume assumption.","tips":["State payback in months, tied to counted handling hours and the injury history.","Show the volume assumed — and that the case holds 20% lower.","Answer the downside question inside the ask, before it's raised."],"focus":["precision","audience"]},
    {"id":"precision-mfg-mid-15","level":"mid","profession":"industrial","title":"Numbers behind 'absence is getting worse'","scenario":"You flag to HR that night-shift absence is 'high and getting worse.' They need the rate, the plant norm, and the trend to know whether this is a spike worth acting on or normal variation.","task":"Rewrite with the current rate, the norm, and the direction over recent months.","tips":["'High' means nothing without the norm — give both.","Show the last three months so 'worse' has evidence.","Precision here decides whether HR treats it as urgent."],"focus":["precision","clarity"],"placeholder":"Night absence is 8% against our 3.5% plant norm, up from 5% two months ago."},
    {"id":"precision-mfg-mid-16","level":"mid","profession":"industrial","title":"One insight from the defect Pareto","scenario":"Your quality report lists defects by type, station, and shift — a full page of counts. The plant manager's only real question: is this one problem or many, and where's the biggest lever?","task":"Write the one insight sentence the data reveals, with the number that proves it.","tips":["Find the concentration — is 65% of it one defect at one station?","Lead with that; the tables become the supporting exhibit.","One clear insight beats a comprehensive but silent report."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-17","level":"mid","profession":"industrial","title":"Corrective actions an auditor can close","scenario":"Your response to the audit finding promises to 'update the changeover checklist and retrain the crew as soon as practical.' The auditor closes findings against owners and dates, not intentions.","task":"Rewrite each action with a named owner and a specific completion date.","tips":["'Update the checklist' gets an owner and a date.","'Retrain as soon as practical' becomes: all three crews signed off by the 30th.","Add how completion will be evidenced — the sign-off sheet."],"focus":["precision","structure"],"placeholder":"1) Checklist revision — J. Moreau, complete June 20. 2) Crew retraining — me, all sign-offs by June 30."},
    {"id":"precision-mfg-mid-18","level":"mid","profession":"industrial","title":"Quantify the capacity answer","scenario":"Sales asks if your line can absorb an extra 5,000-unit order this month. You reply 'we should have some room if things go smoothly.' They need a number they can promise a customer against.","task":"Rewrite with the specific spare capacity, the constraint that caps it, and the condition attached.","tips":["'Some room' becomes: 3,800 units without overtime, 5,000 with one Saturday.","Name the constraint — changeover slots, not machine speed.","Commit to a figure with its condition, not a mood."],"focus":["precision","clarity"],"placeholder":"We can take 3,800 units straight, or the full 5,000 with one approved Saturday shift."},
    {"id":"precision-mfg-mid-19","level":"mid","profession":"industrial","title":"The evidence behind the supplier switch","scenario":"You recommend moving the bracket work to the second machine shop, but your case rests on 'they just seem more on the ball.' Purchasing will want the numbers that decided it before disrupting a supplier.","task":"Rewrite the recommendation with the two or three quantified reasons behind it.","tips":["Turn the impression into its metrics: reject rate, lead time, price per part.","Two hard numbers beat a paragraph of feel.","Lead with the recommendation, then the evidence that survives scrutiny."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-20","level":"mid","profession":"industrial","title":"The maintenance overrun, explained to finance","scenario":"Your budget note says maintenance spend is 'over this month because of some unexpected repairs.' Finance needs the amount, the specific drivers, and — their real question — whether it recurs.","task":"Rewrite with the overrun figure, the named repairs, and the one-time-or-ongoing flag.","tips":["'Some unexpected repairs' becomes two named failures with costs.","State plainly whether it's run-rate or one-time.","The dollar figure and the recurrence flag are the whole answer."],"focus":["precision","concision"],"placeholder":"Maintenance is $14k over on two one-time gearbox failures — not a run-rate change."},
    {"id":"precision-mfg-mid-21","level":"mid","profession":"industrial","title":"The So What on first-pass yield","scenario":"Your report states 'first-pass yield was 94.1% this month' and stops. Leadership doesn't know if that's a win, a slide, or what it means for the rework cell that's been running hot.","task":"Add the So What and Now What in two sentences: what 94.1% means and what you're doing.","tips":["Anchor it: 94.1% against 96% target means 30 hours of rework.","Name the driver behind the gap.","Close with the action and when the number should recover."],"focus":["precision","impact"]},
    {"id":"precision-mfg-mid-22","level":"mid","profession":"industrial","title":"Skeptic-proof 'we're ready for the audit'","scenario":"You tell the plant manager your area is 'ready for next week's customer audit.' A skeptic asks: ready on what evidence — did you run a mock audit, and what's your one weak point?","task":"Rewrite so the readiness claim carries its evidence and names the one open risk.","tips":["Back 'ready' with the mock-audit result: 2 minor findings, both closed.","Name the weak point honestly — calibration records lag by a day.","A claim that names its own risk is more credible, not less."],"focus":["precision","impact"],"placeholder":"We passed Friday's mock audit with two minors, both closed; the one soft spot is same-day calibration filing."},
    {"id":"precision-mfg-mid-23","level":"mid","profession":"industrial","title":"Quantify 'the new fixture helps'","scenario":"Two weeks after engineering installed the drilling fixture, they ask how it's working. Your draft says 'it definitely helps, the parts come out better.' They need measured numbers to justify building three more.","task":"Rewrite with the defect change, the cycle-time effect, and the part count behind them.","tips":["'Comes out better' becomes the hole-position reject rate, before and after.","Report cycle time even if unchanged — they'll ask.","Name the sample: 2,400 parts over two weeks."],"focus":["precision","clarity"]},
    {"id":"precision-mfg-mid-24","level":"mid","profession":"industrial","title":"The dated maintenance ask","scenario":"You request a PM window saying the press 'needs attention in the near future before something lets go.' The planner needs the exact window and the date beyond which failure risk climbs.","task":"Rewrite with the specific window requested and the risk-by date.","tips":["Name the window: Tuesday 6-10 a.m., four hours.","State the by-when: vibration readings say risk climbs past next Friday.","Precise timing lets planning trade runs; vagueness gets deferred."],"focus":["precision","clarity"],"placeholder":"The press needs a 4-hour PM Tuesday 6-10 a.m.; vibration trend says failure risk climbs past next Friday."},
    {"id":"precision-mfg-mid-25","level":"mid","profession":"industrial","title":"Turn the hour-by-hour board into an insight","scenario":"Your new hour-by-hour production board has run for a week, and your note to the plant manager says 'the board is up and it's been useful.' They want what it revealed, with a number.","task":"Write the one data-backed insight the board's first week produced, and the action it prompted.","tips":["Find the pattern the board exposed — the 2-3 p.m. dip after breaks.","State it with the number, then what you changed.","The tool's value is the insight, not that it's mounted."],"focus":["precision","impact"],"placeholder":"The board showed we lose 8% of output in the hour after each break — staggered relief starts Monday."}
  ],
  "executive-presence": [
    {"id":"presence-mfg-mid-01","level":"mid","profession":"industrial","title":"Own the guarding-quote pick","scenario":"The plant manager asked which of two quotes to take for the press guarding retrofit. Your email lays both out neutrally — Fabco is faster, Steelform is cheaper — and leaves the choice to them. They asked you because you run the line.","task":"Rewrite to lead with your recommendation and own it, with the options as support.","tips":["State your pick first — you have a view, so give it.","A neutral menu hands your job back to them.","Present the trade-off, then say which side you land on and why."],"focus":["impact","structure"],"placeholder":"I'd take Fabco — two weeks faster install, and they've done our press line before."},
    {"id":"presence-mfg-mid-02","level":"mid","profession":"industrial","title":"Fact versus judgment on maintenance response","scenario":"Your escalation reads 'maintenance took forever to show up again, which proves they don't care about our line.' The provable fact and your opinion are tangled — and the opinion lets a reader dismiss the fact.","task":"Rewrite separating the measured facts from your interpretation, clearly labeled.","tips":["Fact first: response time was 55 minutes against a 15-minute standard, third time this month.","Then the judgment, marked as yours: 'my read is our line is deprioritized.'","Untangled, the fact stands even if the opinion is argued."],"focus":["impact","clarity"]},
    {"id":"presence-mfg-mid-03","level":"mid","profession":"industrial","title":"Signpost the monthly ops review","scenario":"You're presenting your line's month to the ops review and your instinct is to start at slide one and grind through. Presence sets the frame first: the verdict, the drivers, and what you need.","task":"Write the 2-3 sentence opening that frames the whole review and states your bottom line.","tips":["Open with the month's verdict in one sentence.","Preview the three things you'll cover.","Name upfront the one decision you need from the room."],"focus":["structure","impact"],"placeholder":"Good month with one warning light: I'll cover output, the scrap recovery, and the press bearing that needs a decision today."},
    {"id":"presence-mfg-mid-04","level":"mid","profession":"industrial","title":"The recommendation you're avoiding","scenario":"You believe the cell layout change should wait until after the seasonal ramp, but your note hedges — 'there are pros and cons, it's a tough call either way.' The plant manager needs your call, not your sympathy for the dilemma.","task":"Rewrite to state your recommendation plainly with the one reason that decides it.","tips":["Make the call: delay the layout change to January.","'Pros and cons both ways' is true of everything — say where you land.","One decisive reason carries more than a balanced non-answer."],"focus":["impact","clarity"],"placeholder":"Delay the layout change to January — we can't absorb a week of reduced output during the ramp."},
    {"id":"presence-mfg-mid-05","level":"mid","profession":"industrial","title":"The steady briefing after the forklift near-miss","scenario":"A forklift clipped a pedestrian gate an hour ago; no one was hurt, and you're briefing the plant manager live. You're rattled and it shows — you jump between details and over-apologize.","task":"Script a calm 4-sentence briefing: what happened, current state, next step, your recommendation.","tips":["Lead with the facts in order — panic is contagious, so is calm.","Current state plainly: area cordoned, driver stood down pending review.","End owning the next step, not asking what to do."],"focus":["impact","structure"]},
    {"id":"presence-mfg-mid-06","level":"mid","profession":"industrial","title":"Stop hiding behind 'the team'","scenario":"Explaining the missed changeover target, your draft says 'the team felt the schedule was probably too tight.' You built that schedule. Owning it as 'I under-scheduled the die change' reads far stronger than deflecting to a vague 'the team.'","task":"Rewrite owning the decision and the fix in the first person.","tips":["Say 'I' where you mean yourself — don't launder it through 'the team felt.'","Owning the miss builds more trust than distancing from it.","Then the fix, stated decisively."],"focus":["impact","clarity"],"placeholder":"I under-scheduled the die change — 45 minutes for what's honestly a 70-minute job."},
    {"id":"presence-mfg-mid-07","level":"mid","profession":"industrial","title":"The clean call on the weekend shift","scenario":"The plant manager asks whether to keep running Saturdays through the slow season. You've done the numbers and lean toward stopping, but your draft presents four scenarios without a pick.","task":"Rewrite leading with your recommendation, then the two scenarios that actually differ.","tips":["Recommend: end Saturdays after the 15th.","Two scenarios, not four — the ones that change the answer.","They want your judgment, not a spreadsheet to interpret."],"focus":["impact","structure"],"placeholder":"I recommend ending Saturday shifts after the 15th — demand doesn't cover the premium."},
    {"id":"presence-mfg-mid-08","level":"mid","profession":"industrial","title":"Fact and judgment in the operator note","scenario":"Your note about a struggling operator reads 'Marcus is careless and clearly doesn't take the torque checks seriously.' 'Careless' is a verdict presented as fact — and it isn't provable, while his missed checks are.","task":"Rewrite stating the counted facts first, then your interpretation as an interpretation.","tips":["Fact: four missed torque checks in two weeks, all on the late run.","Judgment, labeled: 'my read is fatigue, not attitude.'","Keep the provable and the inferred visibly separate — it protects him and you."],"focus":["impact","precision"]},
    {"id":"presence-mfg-mid-09","level":"mid","profession":"industrial","title":"Disagreeing with the corporate SOP","scenario":"Corporate wants a network-standard changeover procedure applied at your plant, and you think it adds 20 minutes for no local benefit. Your draft either caves silently or just complains. Presence disagrees with evidence and an alternative.","task":"Write a 3-4 sentence response: the shared goal, your concern with evidence, and your alternative.","tips":["Acknowledge the goal you share before the disagreement.","State the concern with the measured 20 minutes, not resistance.","Offer a concrete alternative — presence proposes, it doesn't just object."],"focus":["impact","structure"]},
    {"id":"presence-mfg-mid-10","level":"mid","profession":"industrial","title":"The headcount ask without the apology","scenario":"You're recommending a permanent second setup tech to the plant manager. Your draft is apologetic — 'I know budget is tight and I hate to ask, but maybe we could possibly look at adding someone.' The cringe undercuts a solid case.","task":"Rewrite as a confident, evidence-backed recommendation with no apology.","tips":["Drop the sorry — a well-founded ask needs none.","State the ask and the number plainly: one setup tech, $68k, pays back in changeover time.","Let the evidence carry the confidence."],"focus":["impact","clarity"],"placeholder":"I'm recommending we add a second setup tech: we lose 9 hours a week waiting on the one we have."},
    {"id":"presence-mfg-mid-11","level":"mid","profession":"industrial","title":"Signpost the escalation","scenario":"You're escalating the recurring wrapper fault to the plant manager after three failed fixes. Your draft is a chronological saga. An escalation with presence frames itself: what's broken, what's been tried, what you need.","task":"Write the 3-sentence framed version: the problem, the attempts, the ask.","tips":["Sentence one: the fault, its frequency, its cost.","Sentence two: three fixes tried, none held — one line each at most.","Sentence three: the specific help you're asking for."],"focus":["structure","clarity"],"placeholder":"The wrapper fault is back — fourth time in six weeks, about 3 hours lost each time."},
    {"id":"presence-mfg-mid-12","level":"mid","profession":"industrial","title":"Own the rush-order trade-off","scenario":"The plant manager asks whether to slot the customer's rush order ahead of Tuesday's scheduled PM. You have a view — the PM protects the whole month — but your draft describes the dilemma without resolving it.","task":"Rewrite stating which you'd choose and the principle behind the choice.","tips":["Make the call and name it as a call: 'my recommendation is the PM holds.'","Give the principle: protect the month over the week.","A resolved trade-off shows judgment; a described one shows only awareness."],"focus":["impact","clarity"],"placeholder":"My call: the PM holds and the rush order ships Wednesday — a press failure costs us far more than one day."},
    {"id":"presence-mfg-mid-13","level":"mid","profession":"industrial","title":"Purge the hedges from the pitch","scenario":"Your improvement pitch reads: 'I sort of think we could maybe cut changeover time quite a bit, possibly by around half, if we kind of pre-staged the tooling.' Every hedge bleeds authority from a claim your data supports.","task":"Rewrite the sentence with zero hedges, keeping only calibrated uncertainty that's real.","tips":["Cut 'sort of', 'maybe', 'kind of' — they're reflexes, not information.","Keep honest uncertainty as a number: '40-50%', not 'quite a bit possibly.'","Hedged everywhere means trusted nowhere."],"focus":["impact","concision"],"placeholder":"Pre-staging tooling cuts changeover time 40-50% — the pilot data is attached."},
    {"id":"presence-mfg-mid-14","level":"mid","profession":"industrial","title":"Calibrated confidence on the unknown cause","scenario":"The plant manager asks what's causing the intermittent seal failures. You don't know yet — you have a leading suspect and two days of testing ahead. Presence is precision about what you know, not false certainty or helpless shrugging.","task":"Write a 2-3 sentence answer that separates what's confirmed, what's suspected, and when you'll know.","tips":["Confirmed: it's temperature-correlated and started Tuesday.","Suspected, labeled as such: the new heater band.","Commit to the date you'll have the answer."],"focus":["impact","precision"],"placeholder":"Confirmed so far: it's temperature-correlated and started Tuesday. My leading suspect is the new heater band — I'll have it confirmed or cleared by Thursday."},
    {"id":"presence-mfg-mid-15","level":"mid","profession":"industrial","title":"Presence on the audit walkthrough","scenario":"You're walking the customer auditor down your line tomorrow. Your instinct is to narrate defensively — explaining away everything before it's questioned. Presence is walking them through what you do, plainly, and answering what's asked.","task":"Script your 3-4 sentence opening at the head of the line: what they'll see and how the area runs.","tips":["Open with the shape: three stations, and the two controls you're proudest of.","Explain the system, not the excuses.","Invite questions — it signals you have nothing to pre-empt."],"focus":["audience","impact"]},
    {"id":"presence-mfg-mid-16","level":"mid","profession":"industrial","title":"The over-caveated yield claim","scenario":"Your update says: 'Yield improved, although it's early, and it might be seasonal, and the sample is smallish, and other factors could be at play.' Four caveats have buried a real 3-point gain your data supports.","task":"Rewrite with the claim first and the one caveat that actually matters.","tips":["Lead with the gain and its number.","Pick the single honest caveat — two weeks of data — and drop the rest.","Reflexive caveating reads as not believing your own work."],"focus":["impact","concision"],"placeholder":"First-pass yield is up 3 points since the fixture change — two weeks in, but consistent across all three crews."},
    {"id":"presence-mfg-mid-17","level":"mid","profession":"industrial","title":"Take a position in the CI meeting","scenario":"The continuous-improvement steering meeting is debating which project gets the engineering hours: your changeover project or packaging's label fix. You've been describing yours neutrally, hoping the data speaks. It doesn't — people do.","task":"Write the 2-3 sentences you'd say to advocate for your project directly.","tips":["State the position: the changeover project should get the hours.","One comparative fact: it returns three times the downtime savings.","Respect the other project while still choosing."],"focus":["impact","clarity"]},
    {"id":"presence-mfg-mid-18","level":"mid","profession":"industrial","title":"The shutdown plan, bottom line first","scenario":"You're presenting the two-week shutdown maintenance plan to plant leadership. Your draft starts with the task list. Presence starts with the verdict: will everything fit, what's at risk, what you need.","task":"Write the 2-3 sentence opening that gives the bottom line before any task detail.","tips":["Verdict first: the plan fits, with one contingency.","Name the at-risk item and its trigger.","The task list is the appendix, not the opening."],"focus":["structure","impact"],"placeholder":"The shutdown plan fits the two weeks, with one flag: the press rebuild has zero slack if parts slip."},
    {"id":"presence-mfg-mid-19","level":"mid","profession":"industrial","title":"Owning the scheduling mistake","scenario":"You sequenced two SKUs back-to-back that share no tooling, and the resulting changeover ate 90 minutes of Tuesday. The plant manager noticed. Your instinct is to blame the ERP's suggestion; you accepted it without checking.","task":"Write a 2-3 sentence account that owns the error and states the guard against repeating it.","tips":["Own it in the first sentence: I sequenced it wrong.","The ERP detail explains, it doesn't excuse — order matters.","Close with the check you've added, not a promise to 'be careful.'"],"focus":["impact","clarity"],"placeholder":"Tuesday's 90-minute changeover was my sequencing error — I accepted the ERP's order without checking tooling overlap."},
    {"id":"presence-mfg-mid-20","level":"mid","profession":"industrial","title":"From options menu to recommendation","scenario":"Your email on the aging compressor lists three paths — repair, rebuild, replace — with costs and risks for each, and ends 'let me know how you'd like to proceed.' The plant manager will bounce it straight back: 'what do you recommend?'","task":"Rewrite the ending so it leads with your recommendation and keeps the other options as one line each.","tips":["Pick one and say why in a sentence.","The rejected options get one line each, showing you weighed them.","'Let me know how to proceed' outsources the thinking you were asked for."],"focus":["structure","impact"],"placeholder":"Recommend the rebuild at $9k: it buys 5+ years, and replacement doesn't pay back unless we add a line."},
    {"id":"presence-mfg-mid-21","level":"mid","profession":"industrial","title":"Steadying the crew after the sister-plant injury","scenario":"News is moving through your crew that an operator at the sister plant lost two fingers in an unguarded press yesterday. You're opening the shift huddle. They need honesty, calm, and what it means here — not rumor management or false cheer.","task":"Script the first 3-4 sentences of the huddle: acknowledge it, say what's known, and what happens on this line today.","tips":["Say it plainly — the crew already knows; evasion reads as spin.","Bridge to here: our presses, our guards, today's extra check.","Calm and specific beats reassuring and vague."],"focus":["audience","impact"]},
    {"id":"presence-mfg-mid-22","level":"mid","profession":"industrial","title":"Signpost the capital pitch","scenario":"You've got fifteen minutes with the plant manager and the controller to pitch the palletizer gate. Presence tells them the shape upfront: the ask, the three parts of the case, and the decision you want today.","task":"Write the 2-3 sentence opening that frames the whole pitch.","tips":["The ask and the number in sentence one.","Preview the three parts: safety record, payback math, install plan.","Name the decision you want before you leave the room."],"focus":["structure","impact"],"placeholder":"I'm asking for $28k for the palletizer gate. I'll cover the injury record, the 14-month payback, and the install plan — and I'd like a decision today."},
    {"id":"presence-mfg-mid-23","level":"mid","profession":"industrial","title":"Fact and judgment on the failed trial","scenario":"The recycled-content trial failed and your report says 'the material is clearly unusable and the supplier oversold it.' The measured results are facts; 'oversold' is your reading — and blending them invites a fight about the reading.","task":"Rewrite with the trial results stated as facts and your conclusion labeled as your conclusion.","tips":["Facts: 11% scrap versus 2% baseline, brittleness failures at station 4.","Judgment, labeled: 'my conclusion is it's not usable at our line speeds.'","Let the supplier argue with your read — the numbers stay standing."],"focus":["precision","impact"]},
    {"id":"presence-mfg-mid-24","level":"mid","profession":"industrial","title":"Holding your ground on the PM window","scenario":"You've asked for the four-hour Sunday PM window and the plant manager pushes back: 'can't it wait until next month?' You have vibration data saying no. The pressure is to fold instantly; presence restates the case calmly once.","task":"Write the 2-3 sentence response that holds the position with evidence, while staying open to being overruled.","tips":["Restate the recommendation, don't just repeat it — lead with the strongest fact.","'The vibration trend says next month is a coin flip on a mid-week failure.'","Acknowledge their authority: you'll schedule either way, but this is your professional read."],"focus":["impact","clarity"],"placeholder":"I'd still take the window Sunday — the vibration trend says waiting a month is a coin flip on a mid-week failure."},
    {"id":"presence-mfg-mid-25","level":"mid","profession":"industrial","title":"Commit to the one-line summary","scenario":"Your quarterly write-up needs a one-line executive summary and you keep softening it, because committing to 'the line is capacity-constrained and needs the second shift decision by August' feels exposed. Vague feels safer. It isn't.","task":"Write the one-line summary that commits to your actual conclusion.","tips":["Say the thing your whole report says.","If the summary is wrong, the report was too — hiding it helps no one.","A committed line gets a decision; a mushy one gets filed."],"focus":["concision","impact"],"placeholder":"Line 2 is capacity-constrained now; without a second-shift decision by August we start missing orders in October."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-mfg-mid-01","level":"mid","profession":"industrial","title":"'When is Line 3 back up?'","scenario":"The plant manager catches you at the line: 'When is 3 back up?' You know the seal kit arrives at noon and it's a two-hour job, but your instinct is to narrate the whole failure before giving a time.","task":"Say a 1-2 sentence answer that gives the time first, then the one dependency.","tips":["Lead with your best estimate: 2:30.","Attach the dependency that could move it — the noon parts delivery.","The failure story is available on request, not by default."],"focus":["clarity","impact"],"placeholder":"Best estimate is 2:30 — the seal kit lands at noon and it's a two-hour job."},
    {"id":"pressure-mfg-mid-02","level":"mid","profession":"industrial","title":"'I don't know' that builds trust","scenario":"In the quality review, the plant manager asks whether the torque drift affected the previous batch too. You genuinely don't know yet. Bluffing is a career risk; a bare 'no idea' reads as unprepared.","task":"Say a 2-sentence answer that admits the gap and commits to closing it by a time.","tips":["Say it cleanly: 'I don't know yet.'","Then the plan: what you'll check and by when.","A dated commitment turns a gap into a next step."],"focus":["clarity","impact"],"placeholder":"I don't know yet — I'll pull the previous batch's torque logs and have an answer by 3 today."},
    {"id":"pressure-mfg-mid-03","level":"mid","profession":"industrial","title":"The auditor's yes-or-no question","scenario":"The customer auditor asks: 'Was this gauge calibrated on schedule?' It was three days late, and your instinct is to open with the calibration vendor's backlog. The auditor asked a yes-or-no question.","task":"Write the answer that responds to the question asked, first, then the one line of context.","tips":["Answer first: no, three days late.","Then the context, briefly — and the fix.","Dodging a checkable fact costs more than the fact does."],"focus":["clarity","precision"],"placeholder":"No — it was three days late. We've since moved calibration tracking into the CMMS with auto-alerts."},
    {"id":"pressure-mfg-mid-04","level":"mid","profession":"industrial","title":"Pushback on your downtime numbers","scenario":"Mid-review, the engineering manager says your downtime figures 'look inflated — that's not what the machine logs show.' Heat rises. Getting defensive loses the room; capitulating without checking loses the truth.","task":"Say a 2-3 sentence response that stays open, states your source, and proposes the reconciliation.","tips":["Take the challenge as data, not attack: 'good — let's reconcile.'","Name your source: operator-logged stops, which catch what sensors miss.","Propose the concrete next step: compare the two logs after the meeting."],"focus":["impact","clarity"]},
    {"id":"pressure-mfg-mid-05","level":"mid","profession":"industrial","title":"'Can you hit Friday?' when it depends","scenario":"Sales asks point-blank if order 5501 ships Friday. Honest answer: yes if tonight's first-off passes, no if it doesn't. Pressure pushes people to either overpromise or hide behind 'we'll see.'","task":"Write a 1-2 sentence answer that gives the conditional verdict precisely.","tips":["Give the verdict and its condition in one breath.","Name when the condition resolves — by 8 tonight.","A precise conditional beats both a false yes and a mushy maybe."],"focus":["clarity","precision"],"placeholder":"Yes if tonight's first-off passes — I'll know by 8 and will text you either way."},
    {"id":"pressure-mfg-mid-06","level":"mid","profession":"industrial","title":"The curveball metric at the tier meeting","scenario":"At the tier meeting the ops director suddenly asks for your line's energy consumption trend — a metric you didn't prep. Waffling for two minutes reads worse than a clean handling.","task":"Say the 2-sentence response: what you know now, and when you'll have the real answer.","tips":["Give what you do know, even if partial: no step changes you're aware of.","Commit to the full answer by a time today.","One clean sentence of 'not prepped, will have it by noon' preserves credibility."],"focus":["clarity","structure"],"placeholder":"I don't have the trend in front of me — nothing's changed operationally that would move it. I'll send the actual curve by noon."},
    {"id":"pressure-mfg-mid-07","level":"mid","profession":"industrial","title":"The loaded 'why does your shift always miss?'","scenario":"In front of the other supervisors, the plant manager asks why your shift 'always misses changeover targets.' The premise is wrong — you've hit four of the last six — but bristling at the framing looks defensive.","task":"Say a 2-sentence answer that corrects the premise with a number, calmly, then addresses the real misses.","tips":["Correct the premise without heat: four of six hit, here are the two misses.","Then own the two: both were the export die, and here's the fix.","Facts delivered calmly beat indignation every time."],"focus":["audience","impact"],"placeholder":"We've hit four of the last six — the two misses were both the export die, and that's what I want to fix."},
    {"id":"pressure-mfg-mid-08","level":"mid","profession":"industrial","title":"Interrupted mid-brief","scenario":"Thirty seconds into your downtime brief, the plant manager cuts in: 'Sorry — just tell me, do I need to call the customer?' Your prepared structure is gone. The skill is landing the answer in one sentence.","task":"Say the one-sentence answer to the question they actually asked.","tips":["Answer the interrupt, not your outline: no call needed, we recover by Thursday.","Offer the detail back as an option, not a resumption.","The brief serves them — when they redirect, follow."],"focus":["concision","impact"],"placeholder":"No — we recover the shortfall by Thursday, so the ship date holds."},
    {"id":"pressure-mfg-mid-09","level":"mid","profession":"industrial","title":"The date you can't commit to","scenario":"The materials manager pushes: 'Just give me a date for when the rework batch clears.' The honest answer depends on a test result you won't have until tomorrow. Pressure wants a date; integrity wants accuracy.","task":"Write the 2-sentence response that offers a dated decision point instead of a fake date.","tips":["Refuse the fake date without refusing the question.","Give the date you'll have the date: tomorrow at 10, after the test.","Offer the range now if it helps them plan: best case Wednesday, worst Friday."],"focus":["precision","clarity"],"placeholder":"I can't give you a real date until tomorrow's test result at 10 — best case Wednesday, worst case Friday."},
    {"id":"pressure-mfg-mid-10","level":"mid","profession":"industrial","title":"The hostile question at the toolbox talk","scenario":"You're announcing the new cut-resistant glove requirement and a senior operator says loudly: 'Twenty years I've run this saw bare-handed — this is paperwork nonsense.' The crew watches how you handle it.","task":"Say a 2-3 sentence response that respects him, holds the line, and keeps the room.","tips":["Acknowledge the experience genuinely — it's real.","Hold the standard without apology: the rule stands, here's the injury data behind it.","Offer the follow-up offline; don't debate for the audience."],"focus":["audience","impact"]},
    {"id":"pressure-mfg-mid-11","level":"mid","profession":"industrial","title":"Two questions at once","scenario":"The controller fires a double-barrel: 'Why is scrap up, and should we be worried about the Anderson order?' Answering them tangled together muddles both. The skill is splitting and sequencing out loud.","task":"Write the response that names both questions and answers each in turn, in 3 sentences.","tips":["Signpost: 'two questions — scrap first, then Anderson.'","Answer each completely before moving on.","The order can be yours; the completeness can't."],"focus":["structure","clarity"],"placeholder":"Two questions there. Scrap: up 1 point on the resin change, fix is running now. Anderson: no risk — it ships from Line 1, which is unaffected."},
    {"id":"pressure-mfg-mid-12","level":"mid","profession":"industrial","title":"The question outside your lane","scenario":"During the plant tour, a corporate visitor asks you about the warehouse's inventory accuracy — not your area. Guessing risks being wrong on the record; a flat 'not my department' sounds like deflection.","task":"Say a 1-2 sentence answer that's honest about the boundary and routes them to the answer.","tips":["Own your lane cleanly: that's warehouse, not mine.","Route, don't drop: name who knows, offer to connect.","Add your adjacent fact if you have one — it shows engagement, labeled as adjacent."],"focus":["clarity","audience"],"placeholder":"That's the warehouse team's number — Rosa would have it exactly. What I can tell you is our line-side counts have been clean all quarter."},
    {"id":"pressure-mfg-mid-13","level":"mid","profession":"industrial","title":"Correcting the boss's number","scenario":"In the ops review, the plant manager tells the group your line's OEE is 81%. It's 74% — the 81% was one good week. Letting it stand sets you up to 'decline' later; correcting clumsily embarrasses them publicly.","task":"Write the one-sentence correction that fixes the record without the sting.","tips":["Correct the number, not the person: 'the month landed at 74 — 81 was our best week.'","Do it now; a wrong baseline compounds.","Brief and matter-of-fact reads as precision, not one-upmanship."],"focus":["audience","precision"],"placeholder":"Small correction — 81 was our best week; the month landed at 74."},
    {"id":"pressure-mfg-mid-14","level":"mid","profession":"industrial","title":"'Give me a straight answer'","scenario":"You've been explaining the changeover delay for a minute when the plant manager cuts through: 'Straight answer — is the export order at risk or not?' Everything you've said was context. Nothing was an answer.","task":"Say the verdict-first answer in one sentence.","tips":["Verdict first, naked: no, it's not at risk.","One condition allowed if it's real.","When someone asks for a straight answer, the window for context has closed."],"focus":["clarity","concision"],"placeholder":"Not at risk — we ship Thursday even if the second die change slips."},
    {"id":"pressure-mfg-mid-15","level":"mid","profession":"industrial","title":"HSE questions after the recordable","scenario":"The HSE manager is interviewing you an hour after an operator lacerated a hand at the trimmer. You're upset and inclined to fill silence with theories. Investigations need facts as you observed them, cleanly separated from speculation.","task":"Write your 3-sentence account: what you saw, what you did, and what you don't yet know.","tips":["Facts you observed, in time order.","Actions you took: stopped the line, first aid, secured the area.","Theories stay out — or come clearly labeled as 'I haven't confirmed this.'"],"focus":["precision","clarity"]},
    {"id":"pressure-mfg-mid-16","level":"mid","profession":"industrial","title":"'What caused it?' before you know","scenario":"Two hours into the unexplained stoppage, the plant manager wants the cause. You have three suspects and no confirmation. Pressure invites either a guess dressed as an answer or a helpless shrug.","task":"Write the 2-3 sentence status: what's eliminated, what's still open, and the next test with its time.","tips":["Report the investigation's shape, not a premature verdict.","Eliminated counts as progress — say what's ruled out.","End with the next test and when it reports."],"focus":["structure","precision"],"placeholder":"Not confirmed yet. We've ruled out the drive and the sensor; the gearbox inspection at 4 should settle it."},
    {"id":"pressure-mfg-mid-17","level":"mid","profession":"industrial","title":"Defending the call that went wrong","scenario":"You ran the marginal material lot after the tests passed, and it caused a quality hold anyway. The plant manager asks, edged: 'Walk me through why you ran it.' The decision was sound; the outcome was bad. Those are different things.","task":"Say a 3-sentence answer that owns the outcome, explains the decision basis, and states what changes.","tips":["Own the outcome first — no 'but' in the first sentence.","Then the basis: the tests it passed, the standard it met.","Close with the added check, so the same inputs now catch it."],"focus":["impact","clarity"],"placeholder":"The hold is on me — I made the run call. It passed both incoming tests we require; clearly those tests miss this failure mode, so I'm adding a third."},
    {"id":"pressure-mfg-mid-18","level":"mid","profession":"industrial","title":"Asked to speculate in front of the customer","scenario":"On the joint call about the complaint, the customer asks you directly: 'So what do you think went wrong?' Root cause isn't confirmed. Speculating on the record can misdirect the investigation and haunt the relationship.","task":"Write the 2-sentence answer that declines to guess while showing the investigation is real.","tips":["Decline the guess explicitly and say why — accuracy over speed.","Show motion: what's being tested, when results land.","Commit to the date they'll get the confirmed answer."],"focus":["audience","precision"],"placeholder":"I'd rather give you the confirmed cause than a guess — the torque study finishes Thursday, and you'll have the full answer Friday."},
    {"id":"pressure-mfg-mid-19","level":"mid","profession":"industrial","title":"Blamed in the room","scenario":"In the shipping review, the logistics lead says the missed truck was 'production's fault — the line released the order late.' The order released on time; staging sat on it. Everyone's looking at you.","task":"Say the 2-sentence response that corrects the record with a fact and moves to the fix, without escalating.","tips":["One fact, no heat: released at 1:40, dock cutoff was 3.","Move immediately to the shared fix — the room rewards whoever ends the blame loop.","Winning the exchange matters less than being right on record and calm."],"focus":["impact","audience"],"placeholder":"The order released at 1:40 against a 3 o'clock cutoff — the gap was in staging. Can we walk that handoff after this?"},
    {"id":"pressure-mfg-mid-20","level":"mid","profession":"industrial","title":"The question you already answered","scenario":"Twenty minutes after you explained the hold disposition, the quality director asks the same question again, slightly reworded. Irritation would be fatal; they may be testing consistency, or they simply missed it.","task":"Write the same answer, fresh, in 2 sentences — no edge, no 'as I said.'","tips":["Never 'as I mentioned' — it scores a point and loses the room.","Answer as if for the first time, tighter than before.","Consistency under repetition is what they remember."],"focus":["audience","concision"]},
    {"id":"pressure-mfg-mid-21","level":"mid","profession":"industrial","title":"The VP's walk-around question","scenario":"The regional VP pauses at your line: 'What's the biggest problem on this line right now?' You have thirty seconds and one shot. Both a rosy 'all good!' and a rambling gripe list waste it.","task":"Say the 2-sentence answer: the one real constraint, with its number, and what's being done.","tips":["Name one problem — the real constraint, not the safest one.","Attach its number: the packer costs us 5 hours a week.","End on the action in motion, not a complaint."],"focus":["clarity","impact"],"placeholder":"The case packer — it costs us about 5 hours a week in short stops. The sensor upgrade that fixes it is in this quarter's plan."},
    {"id":"pressure-mfg-mid-22","level":"mid","profession":"industrial","title":"'How confident are you?'","scenario":"You've committed to restarting Line 2 by Thursday and the plant manager asks: 'How confident?' 'Pretty confident' carries no information. Calibration does: a number or odds, with the one thing that would break it.","task":"Write the 1-2 sentence calibrated answer.","tips":["Give real odds: 90% for Thursday.","Name the tail risk: the one part that could slip it to Friday.","Calibrated answers let them plan; vibes make them re-check you."],"focus":["precision","impact"],"placeholder":"Ninety percent for Thursday — the only thing that moves it is if the bearing housing arrives damaged, and then it's Friday."},
    {"id":"pressure-mfg-mid-23","level":"mid","profession":"industrial","title":"Challenged on the overtime cost","scenario":"You've just asked for Saturday overtime and the controller counters in the moment: 'That's $2,000 — why should we spend it?' The justification is solid but you have ten seconds, live, not a memo.","task":"Say the 2-sentence answer that puts the cost against the alternative, in numbers.","tips":["Frame it as the cheaper option: $2,000 versus a $7,500 late penalty.","One comparison, cleanly — don't stack three arguments.","End with the deadline the math expires on."],"focus":["impact","precision"],"placeholder":"It's $2,000 against a $7,500 late-shipment penalty if we miss Monday — and the math works only if we decide by tomorrow."},
    {"id":"pressure-mfg-mid-24","level":"mid","profession":"industrial","title":"The question behind the question","scenario":"After one defect escape, the plant manager asks: 'Is quality slipping on your line?' The literal answer is no — one escape, metrics flat. But the real question is 'should I be worried?' Answer only the literal one and the worry stays.","task":"Write the 2-3 sentence answer that addresses both the stated and the real question.","tips":["Answer the metric question with the numbers: flat at 96% yield, one escape in six weeks.","Then the real one: here's why this escape doesn't signal a trend — and what would.","Naming what WOULD worry you is what actually reassures."],"focus":["audience","clarity"],"placeholder":"No — yield's flat at 96% and this is one escape in six weeks. It was a new failure mode, not a control slipping; if I see it twice, you'll hear from me same-day."},
    {"id":"pressure-mfg-mid-25","level":"mid","profession":"industrial","title":"Rapid-fire round at the ops review","scenario":"The ops director is running the review at speed: 'Line 2 recovery?' 'Audit prep?' 'The Hendricks order?' Each answer gets ten seconds before the next question. Anything beyond a headline gets cut off.","task":"Write your three ten-second answers, one line each.","tips":["Headline only: status, number, next step if it fits.","Practice the drop — everything you know minus what they need is silence.","A tight answer earns the follow-up question; a long one earns the interruption."],"focus":["concision","clarity"],"placeholder":"Line 2: back up, recovery complete Thursday. Audit: mock passed, two minors closed. Hendricks: ships Friday as committed."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-mfg-mid-01","level":"mid","profession":"industrial","title":"Before and after for the changeover pitch","scenario":"You're pitching the pre-staged tooling program to the plant manager. Your draft is a list of SMED techniques. What moves a decision is the gap: where changeovers are today, where they land after, and the bridge between.","task":"Write the 2-3 sentence before/after opening for the pitch.","tips":["Before: 62 minutes, twice a shift, 2 hours of capacity gone daily.","After: 35 minutes with pre-staging — the pilot already proved it.","The bridge: one cart, one checklist, two weeks of practice per crew."],"focus":["structure","impact"],"placeholder":"Today a changeover costs us 62 minutes; the crew that pre-stages tooling does it in 35."},
    {"id":"narrative-mfg-mid-02","level":"mid","profession":"industrial","title":"Make the stakes human","scenario":"Your case for automating the manual pack station cites 'ergonomic risk factors and repetitive strain exposure.' Accurate, bloodless, ignorable. The reality: two packers wore wrist braces last year and one needed surgery.","task":"Rewrite the stakes in one or two sentences a decision-maker feels.","tips":["Abstract risk becomes named consequence: two wrist braces and one surgery in twelve months.","Keep it factual — human stakes don't need embellishment.","Then the number that scales it: 4,000 lifts per shift, every shift."],"focus":["impact","audience"],"placeholder":"Two of our packers wore wrist braces last year and one needed surgery — that station demands 4,000 lifts a shift."},
    {"id":"narrative-mfg-mid-03","level":"mid","profession":"industrial","title":"Disarming 'we tried that before'","scenario":"You're proposing a 5S reset of the tool cribs, and you know exactly what the plant manager will say: 'we did 5S in 2019 and it didn't stick.' If the objection lands before you address it, the pitch is over.","task":"Write the 2-3 sentences that raise and answer the objection before they do.","tips":["Name it yourself: 'we tried this in 2019 and it faded — here's why this is different.'","The difference must be structural: audits owned by leads, not a launch event.","Pre-empting the objection converts your biggest skeptic point into credibility."],"focus":["impact","structure"],"placeholder":"You'll remember we ran 5S in 2019 and it faded within a quarter — because nobody owned the audits. This version starts there."},
    {"id":"narrative-mfg-mid-04","level":"mid","profession":"industrial","title":"The story of one escaped part","scenario":"You're making the case for quality-at-source checks to the supervisors' group. Your slides show escape rates. What lands is a story: the one bracket that passed three stations, shipped, and came back with a customer complaint attached.","task":"Write the 3-4 sentence story of the one part, ending on the lesson.","tips":["Follow the part: made at 6 a.m., through three stations, onto the truck.","Every station assumed the previous one checked.","Land the lesson in one line: the defect was visible the whole way."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-mid-05","level":"mid","profession":"industrial","title":"The pilot that de-risks the ask","scenario":"You want kanban cards for the parts crib but the full rollout means changing how every crew orders parts. Asking for the whole change invites a no. A two-rack, one-month pilot is nearly impossible to refuse.","task":"Write the 2-3 sentence pilot proposal, with its success measure and review date.","tips":["Shrink the ask until refusing feels unreasonable.","Define success now: stockouts on those racks go to zero.","Name the review date and the walk-away — this is a test, not a commitment."],"focus":["structure","impact"],"placeholder":"Give me two racks and one month: kanban cards on high-turn parts, success is zero stockouts, and we review July 8 with the data."},
    {"id":"narrative-mfg-mid-06","level":"mid","profession":"industrial","title":"Selling the new check to the crew","scenario":"You're introducing a torque-verification step at the huddle. To the crew it's one more task on a full shift. 'Because quality requires it' persuades no one. The real story: this check is what keeps the rework pile off their Friday.","task":"Script the 3-sentence huddle pitch that sells the step in the crew's own interest.","tips":["Frame it in their currency: ten seconds now versus rebuilding units Friday.","Use the recent pain they remember — last month's 300-unit rework weekend.","Respect their time: say what it costs honestly, then what it buys."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-mid-07","level":"mid","profession":"industrial","title":"From firefighting to planned maintenance","scenario":"You're pitching the preventive-maintenance expansion to the plant manager. Your draft lists PM tasks and frequencies. The persuasive frame is the before/after world: from nights rebuilt around breakdowns to failures you saw coming.","task":"Write the 2-3 sentence framing that contrasts the two worlds, with one number each.","tips":["Before: 14 unplanned stops last quarter, every one at the worst time.","After: the benchmark plant runs 4, because they catch them in the vibration data.","The ask is the bridge: 6 tech-hours a week buys the difference."],"focus":["structure","impact"],"placeholder":"Last quarter we ate 14 unplanned breakdowns; the sister plant had 4 — the difference is 6 hours a week of planned checks."},
    {"id":"narrative-mfg-mid-08","level":"mid","profession":"industrial","title":"The cost of doing nothing","scenario":"Your pitch to rebuild the aging press keeps getting deferred because the price is visible and the risk isn't. The persuasion job: make 'do nothing' a decision with a price tag, not a neutral default.","task":"Write the 2-3 sentences that price the do-nothing option.","tips":["Doing nothing costs: rising minor stoppages, and a catastrophic failure lands a 3-week lead time.","Use the trend: minor faults doubled in six months — that's the curve we're on.","Frame the choice as two prices, not a price versus free."],"focus":["impact","precision"],"placeholder":"Deferring isn't free: minor press faults have doubled in six months, and an unplanned failure means three weeks down waiting on parts."},
    {"id":"narrative-mfg-mid-09","level":"mid","profession":"industrial","title":"Vendor consolidation and the single-source fear","scenario":"You're proposing to consolidate three fastener suppliers into one for price and consistency. The obvious objection — 'what if the single source fails us?' — will kill it unless your pitch resolves it head-on.","task":"Write the pitch's objection-handling passage in 2-3 sentences.","tips":["State the fear plainly before they do — naming it disarms it.","Answer with structure: a qualified backup on file, 4 weeks of safety stock.","Show you weighed the risk, not that you didn't see it."],"focus":["impact","structure"]},
    {"id":"narrative-mfg-mid-10","level":"mid","profession":"industrial","title":"The cross-training case","scenario":"Only one person on your shift can run the laser cutter, and your cross-training proposal reads as a nice-to-have. The story that persuades: the week Devon was out and the laser sat idle while orders queued.","task":"Write the 2-3 sentence case built on that week, with the numbers it cost.","tips":["Open with the story: Devon's sick week, the laser dark, 900 units queued.","Generalize it: four machines on this shift have exactly one qualified operator.","The ask closes the exposure: two backups per machine by September."],"focus":["impact","audience"],"placeholder":"When Devon was out in March, the laser sat idle for four days and 900 units queued — and four of our machines have exactly one qualified operator."},
    {"id":"narrative-mfg-mid-11","level":"mid","profession":"industrial","title":"The andon proposal, before and after","scenario":"You want andon lights on the line so operators can flag problems without leaving station. Your draft explains the technology. The pitch that works contrasts response times: today's find-the-supervisor walk versus the light.","task":"Write the before/after contrast in 2 sentences, with the response-time numbers.","tips":["Before: an operator leaves station, finds you, explains — 12 minutes average to response.","After: light on, response under 2 — the benchmark line already runs this.","Sell the gap, not the hardware."],"focus":["structure","precision"],"placeholder":"Today a line problem waits an average of 12 minutes while the operator walks to find help; with andon lights it's under 2."},
    {"id":"narrative-mfg-mid-12","level":"mid","profession":"industrial","title":"Persuading the scheduler","scenario":"You need the scheduler to hold Thursday morning open for the long die change, and they're measured on schedule density, not your changeover pain. A pitch framed around your problem loses; one framed around theirs wins.","task":"Write the 2-3 sentence request framed in the scheduler's interest.","tips":["Lead with what they get: a clean Thursday beats a blown Friday recovery.","Show the history: the last two crammed die changes each blew a day of their schedule.","Make the trade explicit — one planned gap versus unplanned chaos."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-mid-13","level":"mid","profession":"industrial","title":"Lead with the person, not the regulation","scenario":"Your guarding-retrofit request opens with the machinery-safety standard it addresses. Compliance framing gets queued; consequence framing gets funded. The point-of-operation gap is eight inches from where Rosa's hands work all shift.","task":"Rewrite the opening 2 sentences leading with the human exposure.","tips":["Open at the point of exposure: a hand works eight inches from an unguarded nip point, 8 hours a shift.","The regulation becomes supporting evidence, not the headline.","One person, named role, real distance — then scale it to the crew."],"focus":["impact","audience"],"placeholder":"Every shift, an operator's hands work eight inches from the press's unguarded nip point."},
    {"id":"narrative-mfg-mid-14","level":"mid","profession":"industrial","title":"Translate the scrap project into trucks","scenario":"Your scrap-reduction proposal promises 'a 1.5-point improvement in material yield.' The plant manager thinks in dollars and shipments, not yield points. Persuasion speaks the listener's units.","task":"Rewrite the benefit in the plant manager's units: dollars per year and what it equals.","tips":["Convert: 1.5 points is $110k of material a year.","Then make it vivid in plant terms: a full truckload of good product every month.","Abstract percentages inform; concrete equivalents persuade."],"focus":["precision","impact"],"placeholder":"That 1.5 yield points is $110k of material a year — a full truckload of sellable product every month that currently goes in the grinder."},
    {"id":"narrative-mfg-mid-15","level":"mid","profession":"industrial","title":"The second-shift pitch, objection first","scenario":"You're proposing a second shift on Line 1 and the cost objection is certain: supervision, premiums, training. Burying the costs makes you look evasive; leading with them and beating them makes you credible.","task":"Write the passage that states the full cost honestly, then shows the return that clears it.","tips":["Name the whole cost first: $340k a year, loaded.","Then the return: $520k of demand we currently turn away or outsource.","Honesty about cost is what makes the return believable."],"focus":["impact","structure"]},
    {"id":"narrative-mfg-mid-16","level":"mid","profession":"industrial","title":"From trial data to decision story","scenario":"The gasket-supplier trial produced a page of results: zero leaks in 500, cycle time flat, cost down 8%. Your draft presents the data and stops. Data doesn't decide; a framed choice does.","task":"Write the 2-3 sentence decision story: what the data means, the choice it points to, and the ask.","tips":["Data becomes meaning: the cheaper gasket is proven equal.","Meaning becomes choice: switch at the next PO or keep paying 8% for no benefit.","End with the ask and its date: approve the switch this week."],"focus":["structure","impact"],"placeholder":"The trial settles it: zero leaks in 500 units at 8% lower cost. Every PO we delay is money spent on no benefit — I'm asking to switch effective next order."},
    {"id":"narrative-mfg-mid-17","level":"mid","profession":"industrial","title":"Persuading maintenance to shift the PM","scenario":"You want maintenance to move the packer PM from Wednesday day-shift to Sunday, and their planner guards the weekend slots. Your draft argues from your production schedule — their least favorite argument.","task":"Write the 2-3 sentence request framed around what the planner cares about.","tips":["Their currency: uninterrupted work windows and no emergency callouts.","The Wednesday slot gets them 90 minutes before production pressure resumes; Sunday gets four clean hours.","Fewer mid-week emergencies is their win too — say it with the callout count."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-mid-18","level":"mid","profession":"industrial","title":"Urgency without alarmism","scenario":"The bearing vibration on the main drive has crossed the warning threshold. Your note needs to move the repair up the queue without reading like panic — cry wolf once and your next warning gets discounted.","task":"Write the 2-3 sentence escalation that creates calibrated urgency.","tips":["Anchor to the measurement, not adjectives: crossed threshold Tuesday, trending 8% a week.","Give the window: at this rate, four to six weeks to forced stop.","State the cheap-now/expensive-later gap — that's the urgency, delivered calm."],"focus":["impact","clarity"],"placeholder":"The main drive bearing crossed its vibration threshold Tuesday and is trending up 8% a week — planned, it's a 4-hour swap; run to failure, it's three days."},
    {"id":"narrative-mfg-mid-19","level":"mid","profession":"industrial","title":"The training budget tied to the defect trend","scenario":"Your request for setup-training budget cites 'skills development needs.' The plant manager sees a cost. The persuasive link sits in your own data: 70% of this quarter's defects trace to setups done by the three newest techs.","task":"Write the 2-sentence case that ties the training spend to the defect number.","tips":["Lead with the correlation: 70% of defects trace to the three newest setups.","Price both sides: $6k of training against $40k of quarterly rework.","A cost that cancels a bigger cost isn't a cost."],"focus":["impact","precision"],"placeholder":"Seventy percent of this quarter's defects trace to setups by our three newest techs — $6k of training against $40k a quarter of rework."},
    {"id":"narrative-mfg-mid-20","level":"mid","profession":"industrial","title":"'Robots take jobs' — the reframe","scenario":"Word is out that you're proposing to automate the pack station, and the crew has heard 'automation' as 'layoffs.' At the huddle you need the true story told straight: the station is the injury spot, and nobody loses a job.","task":"Script the 3-sentence huddle message that addresses the fear directly and honestly.","tips":["Say the fear out loud first — pretending it isn't in the room loses the room.","Give the commitment plainly if it's real: nobody loses a job; packers move to machine tending.","Anchor to what they know: that station put two of us in wrist braces."],"focus":["audience","impact"]},
    {"id":"narrative-mfg-mid-21","level":"mid","profession":"industrial","title":"One number to carry the story","scenario":"Your downtime presentation has eleven statistics and the room remembers none of them. Persuasion travels on one number people can repeat in the hallway afterward.","task":"Pick the one number for the changeover story and write the sentence that makes it stick.","tips":["Choose the number that implies the action: 2 hours of capacity lost daily.","Make it repeatable: 'we lose a shift a week to changeovers.'","Every other stat becomes backup — spoken only if asked."],"focus":["precision","impact"],"placeholder":"We lose a full shift every week to changeovers — that's the whole story in one number."},
    {"id":"narrative-mfg-mid-22","level":"mid","profession":"industrial","title":"The analogy that lands","scenario":"The plant manager isn't feeling the changeover project's urgency — 60 minutes just doesn't sound like much. An analogy can carry what the number doesn't: a pit crew turns a race car in seconds because everything is staged before the car arrives.","task":"Write the 2-sentence analogy passage that reframes the changeover and lands back on your line's number.","tips":["Keep the analogy short and return to the plant fast.","The point of the analogy is one transferable idea: stage everything before the machine stops.","Land on your number: our 62 minutes has 25 minutes of 'car in the pit' waste."],"focus":["audience","clarity"]},
    {"id":"narrative-mfg-mid-23","level":"mid","profession":"industrial","title":"Sequence the pitch","scenario":"Your improvement pitch for the label-splice fix has everything — problem, data, solution, cost, ask — scattered in whatever order you thought of it. Persuasion has a spine: problem, cost of the problem, the fix, proof it works, the ask.","task":"Write the five-sentence pitch, one sentence per beat, in that order.","tips":["One sentence per beat keeps you honest about each.","The cost beat is where most pitches go vague — put the number there.","The ask names amount, owner, and date."],"focus":["structure","clarity"],"placeholder":"Label splices stop Line 2 nine times a week. Each stop costs 11 minutes — about $2,300 a month."},
    {"id":"narrative-mfg-mid-24","level":"mid","profession":"industrial","title":"Close with the ask","scenario":"Your persuasive memo about the tooling upgrade ends with 'hopefully this is something we can consider going forward.' After 400 good words, the close dissolves into fog. Decisions need a handle to grab.","task":"Rewrite the closing 1-2 sentences with a specific ask, owner, and date.","tips":["Name the decision: approve $12k for the die upgrade.","Give it a date and what the date protects: by the 15th to hit the shutdown window.","'Something to consider' is how funded ideas die."],"focus":["impact","concision"],"placeholder":"I'm asking for approval of the $12k die upgrade by the 15th, so the work lands in the July shutdown."},
    {"id":"narrative-mfg-mid-25","level":"mid","profession":"industrial","title":"The elevator version","scenario":"You have the plant manager for the length of the walk from the line to their office — forty seconds — and your changeover project is stalled in their inbox. The full pitch is twelve slides. The walk gets three sentences.","task":"Write the 3-sentence elevator version: the gap, the proof, the ask.","tips":["The gap: a shift a week lost to changeovers.","The proof: the pilot cut it 40% with zero spend.","The ask: 30 minutes Thursday to approve the rollout."],"focus":["concision","impact"],"placeholder":"We lose a shift a week to changeovers, and the pilot already cut that 40% with zero capital. I need 30 minutes Thursday to walk you through the rollout."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-mfg-mid-01","level":"mid","profession":"industrial","title":"Telling the plant manager you'll miss the month","scenario":"It's the 22nd and the math no longer works: the line will finish about 1,800 units short of April's plan. Your draft opens with two paragraphs on the difficult conditions before the number appears anywhere.","task":"Rewrite the opening 2 sentences: the miss first, plainly, then the primary cause.","tips":["Sentence one: we will miss April by about 1,800 units.","No cushion of caveats — the reader hunts through them for the point.","Cause and recovery follow the headline, not precede it."],"focus":["clarity","impact"],"placeholder":"We will miss April's plan by about 1,800 units — the press rebuild ran nine days instead of four."},
    {"id":"hard-mfg-mid-02","level":"mid","profession":"industrial","title":"The slipped ship date, told to customer service","scenario":"Order 7734 will ship Tuesday, not Friday as promised — the quality hold ate the buffer. Customer service has to call the customer, and your draft makes them dig through the hold's backstory to find the new date.","task":"Write the 2-3 sentence notice that gives them the new date first and something they can say.","tips":["Lead with what changed: Friday is now Tuesday.","One plain-language reason they can repeat to the customer.","End with what's firm: Tuesday is committed, not hoped."],"focus":["clarity","audience"],"placeholder":"Order 7734 slips from Friday to Tuesday — a quality check on the seals took the buffer. Tuesday is firm."},
    {"id":"hard-mfg-mid-03","level":"mid","profession":"industrial","title":"Feedback on the repeated quality miss","scenario":"The same operator has passed three out-of-spec parts to the next station in two weeks. Your instinct swings between a vague 'be more careful' and frustration. Neither is feedback; one is noise, the other is venting.","task":"Script the 3-sentence feedback: the specific pattern, the impact, and the specific change.","tips":["Specific and counted: three escapes in two weeks, all on the diameter check.","Impact without drama: each one stops the next station for twenty minutes.","The ask is behavioral: gauge every fifth part, log the reading."],"focus":["audience","clarity"]},
    {"id":"hard-mfg-mid-04","level":"mid","profession":"industrial","title":"Declining the rush order","scenario":"Sales wants a rush order inserted into this week's schedule. Saying yes breaks two committed ship dates for other customers. Your draft no is so apologetic and hedged that it reads like a maybe — which means the fight isn't over.","task":"Write the 2-sentence decline that is unambiguous and gives the real reason.","tips":["Say no in the first sentence, without 'unfortunately' scaffolding.","The reason is the trade: this rush breaks two committed dates.","Offer the real alternative if one exists: next week, or partial quantity Friday."],"focus":["clarity","impact"],"placeholder":"I can't insert the rush this week — it breaks committed ship dates for two other customers. I can do the full quantity Wednesday next week, or 400 units this Friday."},
    {"id":"hard-mfg-mid-05","level":"mid","profession":"industrial","title":"The fix that didn't hold","scenario":"Maintenance replaced the wrapper's clutch Friday and called it fixed; it failed again Monday morning. You need the lead tech back, and your message needs to say 'your fix failed' without starting a turf war.","task":"Write the 2-3 sentence message: the fact of the failure, no blame theater, and the specific ask.","tips":["State the fact neutrally: same fault, 72 hours after the repair.","Skip 'apparently it wasn't actually fixed' — sarcasm costs you the relationship.","Ask for what's next: the deeper look you both suspected it needed."],"focus":["audience","impact"],"placeholder":"The wrapper fault is back — same symptom, 72 hours after the clutch swap. I think this confirms it's upstream of the clutch; can we get Denny on it today?"},
    {"id":"hard-mfg-mid-06","level":"mid","profession":"industrial","title":"Ending the temp's assignment","scenario":"After four weeks, the temp on the pack line isn't reaching rate and the coaching hasn't moved it. You're ending the assignment today. They deserve a direct, respectful conversation — not a mumbled 'the agency will call you.'","task":"Script the 3-sentence conversation: the decision, the honest reason, and the clean close.","tips":["The decision first, kindly and unmistakably: today is your last day here.","The reason is factual, not personal: the rate didn't come up, and it needs to.","Respect the person: thank them for real effort, keep it short."],"focus":["audience","clarity"]},
    {"id":"hard-mfg-mid-07","level":"mid","profession":"industrial","title":"Announcing mandatory Saturday overtime","scenario":"The recovery plan requires mandatory overtime this Saturday — the first mandatory weekend in a year, and the crew will hate it. Softening it into 'we'd really appreciate if people could come in' misleads them about whether it's optional.","task":"Script the huddle announcement in 3 sentences: the decision, the reason, and what's being done to make it fair.","tips":["Say 'mandatory' if it's mandatory — kindness isn't ambiguity.","One honest reason: the 1,800-unit hole and the customer commitment.","Fairness details matter: premium pay confirmed, next Saturday protected."],"focus":["clarity","audience"]},
    {"id":"hard-mfg-mid-08","level":"mid","profession":"industrial","title":"Recommending the batch be scrapped","scenario":"The 2,000-unit batch with the torque issue can't be economically reworked — your analysis says scrap it, a $9,000 write-off. Your draft to the plant manager buries the recommendation under every rework option you already ruled out.","task":"Write the 2-3 sentence recommendation: the call, the cost, and the one-line rationale.","tips":["Lead with the recommendation: scrap the batch.","The number goes next to it — $9,000 — not hidden below.","One line on why rework loses: $14k of labor to save $9k of product."],"focus":["impact","precision"],"placeholder":"Recommend we scrap the 2,000-unit hold batch — a $9k write-off. Rework costs $14k of labor to save $9k of product."},
    {"id":"hard-mfg-mid-09","level":"mid","profession":"industrial","title":"Telling engineering their fixture is the problem","scenario":"Your defect data points squarely at the new fixture engineering installed last month — the one they're proud of. The message has to survive their defensiveness, which means leading with data, not verdicts.","task":"Write the 2-3 sentence message: the correlation, stated as data, and the joint next step.","tips":["Lead with the data: defects tripled the week the fixture went in, on that station only.","'The fixture is causing it' is a conclusion — offer it as the hypothesis the data suggests.","Invite them into the diagnosis: can we run a shift on the old fixture and compare?"],"focus":["audience","precision"],"placeholder":"Hole-position defects tripled the week the new fixture went in, and they're confined to that station — can we run a shift on the old fixture Thursday and compare?"},
    {"id":"hard-mfg-mid-10","level":"mid","profession":"industrial","title":"The vacation request during shutdown","scenario":"Your best setup tech has asked for vacation during the July shutdown — the one week the whole maintenance plan depends on his skills. You have to say no, and he'll be unhappy. A fudge now becomes a worse conversation in July.","task":"Write the 2-3 sentence answer: the no, the specific reason, and what you can offer.","tips":["The no comes first and stays a no.","The reason is concrete: the press rebuild needs your certification, that week only.","Give what's actually yours to give: first pick of any other week, in writing."],"focus":["clarity","audience"],"placeholder":"I can't approve shutdown week — the press rebuild needs your certification and there's no second. Any other week this summer is yours, first pick, and I'll put that in writing."},
    {"id":"hard-mfg-mid-11","level":"mid","profession":"industrial","title":"Opening the written-warning conversation","scenario":"After the verbal warning and the coaching plan, the safety violations continued, and today's conversation comes with a written warning. The hardest part is the first sentence — most supervisors circle for five minutes and the employee hears the circling as hope.","task":"Script the first 2 sentences of the conversation, stating what this meeting is.","tips":["Name the meeting in sentence one: this is a written warning.","No small talk runway — it reads as dread, and they feel it.","Then the specific incident that triggered it, factually."],"focus":["clarity","audience"]},
    {"id":"hard-mfg-mid-12","level":"mid","profession":"industrial","title":"Dropping the vendor","scenario":"After three quarters of documented quality problems, you're moving the fastener business away from a vendor whose rep you've worked with for years. The notification should be clean: the decision, the record it rests on, and no false doors left open.","task":"Write the 2-3 sentence notification.","tips":["The decision first, as a decision — not 'we're thinking about.'","The record: 8% rejects across three quarters against a 1% standard, raised three times.","Don't soften with 'maybe down the road' unless you mean it."],"focus":["clarity","impact"],"placeholder":"We're moving our fastener business effective the August PO. Reject rates held at 8% across three quarters against the 1% standard we raised three times — the decision is final."},
    {"id":"hard-mfg-mid-13","level":"mid","profession":"industrial","title":"Your error caused the miss","scenario":"The Friday shipment missed because you transposed two SKUs in the schedule — the line built the wrong product for six hours. The plant manager will hear about it within the hour. The only question is whether they hear it from you first.","task":"Write the 2-3 sentence message that owns it: the error, the impact, and the guard now in place.","tips":["Own it in sentence one: my scheduling error.","The impact stated plainly: six hours on the wrong SKU, Friday's shipment missed.","Close with the concrete check added — not 'I'll be more careful.'"],"focus":["impact","clarity"],"placeholder":"Friday's miss was my error — I transposed two SKUs in the schedule and the line built the wrong product for six hours."},
    {"id":"hard-mfg-mid-14","level":"mid","profession":"industrial","title":"The lapsed certification","scenario":"Your most experienced operator's crane certification lapsed last month — an admin slip, nobody's watching it. Until she requalifies, she's off crane duties, and she'll take it as an insult to twenty years of clean operation.","task":"Script the 2-3 sentence conversation: the fact, the immediate consequence, and the fast path back.","tips":["Separate the person from the paperwork: this is about a date, not your skill.","The consequence is non-negotiable and stated once: off crane duties until requalified.","Make the path short and owned: recert booked Thursday; you're back Friday."],"focus":["audience","impact"]},
    {"id":"hard-mfg-mid-15","level":"mid","profession":"industrial","title":"The audit finding, told first","scenario":"The internal audit found that your line's first-off inspections were skipped on eleven occasions last quarter — a real finding, and it will reach the plant manager through the audit report Friday. Telling them now, yourself, changes everything about how it lands.","task":"Write the 2-3 sentence heads-up: the finding, no excuses, and the fix already moving.","tips":["Deliver it straight: the audit will show eleven skipped first-offs, on my line.","Resist context-cushioning — the report won't have any.","The fix already in motion is your credibility: sign-off now interlocked with line start."],"focus":["clarity","impact"],"placeholder":"Before Friday's audit report reaches you: it found eleven skipped first-off inspections on my line last quarter. That's accurate, and as of Monday the sign-off is interlocked with line start."},
    {"id":"hard-mfg-mid-16","level":"mid","profession":"industrial","title":"Peer feedback on the handovers","scenario":"The supervisor you hand over to keeps inheriting your shift's problems undocumented — and you keep inheriting his. His handover notes are two vague lines. You're peers; you can't instruct him, but the current silence is costing both shifts.","task":"Write the 2-3 sentence peer conversation opener: the shared problem, one concrete example, and a proposal.","tips":["Frame it as the shifts' problem, not his character.","One dated example each way keeps it fair — include one you fumbled too.","Propose the fix as an experiment: the 3-line template, two weeks, then compare."],"focus":["audience","clarity"]},
    {"id":"hard-mfg-mid-17","level":"mid","profession":"industrial","title":"The project is over budget","scenario":"The palletizer-gate install you championed is tracking $7k over its $28k budget — the mounting steel was triple the estimate. The plant manager approved this on your numbers. Waiting until it's $12k over makes the same conversation strictly worse.","task":"Write the 2-3 sentence early warning: the overrun, the cause, and the choice you're presenting.","tips":["The number first: tracking $7k over, and here's why.","No spin on the cause — your estimate missed, say so.","Bring the decision, not just the problem: absorb it, descope the guarding trim, or pause."],"focus":["clarity","precision"],"placeholder":"The gate install is tracking $7k over the $28k I brought you — the mounting steel came in triple my estimate. Three options, and my recommendation is below."},
    {"id":"hard-mfg-mid-18","level":"mid","profession":"industrial","title":"Refusing the shortcut","scenario":"You're behind, and your lead hand proposes skipping first-off inspection on the repeat job to save forty minutes — 'we ran this exact SKU Tuesday, it'll be fine.' He's probably right that it would be fine. The answer is still no, and it needs to not sound like a lecture.","task":"Script the 2-sentence refusal that holds the standard and respects the thinking.","tips":["Credit the logic before refusing it — he's solving the right problem.","The no rests on the principle: the check exists for the day 'probably fine' isn't.","Redirect the energy: where else can we find the forty minutes?"],"focus":["impact","clarity"],"placeholder":"You're right that it'd probably run clean — and first-off exists exactly for the day 'probably' misses. Let's find the forty minutes in the stage-ahead instead."},
    {"id":"hard-mfg-mid-19","level":"mid","profession":"industrial","title":"The popular teammate is moving lines","scenario":"Plant leadership is moving your best all-rounder to Line 5 permanently — their call, not yours, and your crew will read it as the shift being raided. You disagree with the decision but you're delivering it, which means owning it in the room.","task":"Script the 3-sentence huddle announcement: the decision, the honest framing, and what happens next.","tips":["Deliver it as a decision made, not one you're distancing from — 'they decided' poisons the well.","Honest without editorializing: it's a loss for us and a real opportunity for Priya.","Next steps beat sympathy: who's cross-training into the gap, starting when."],"focus":["audience","impact"]},
    {"id":"hard-mfg-mid-20","level":"mid","profession":"industrial","title":"The line is down for a week","scenario":"The gearbox failure means Line 2 is down at least five days waiting on parts — and Line 2 is half your crew's hours. Rumors will fill any information gap within the hour. The announcement needs the facts, the plan for people, and no false cheer.","task":"Write the 3-4 sentence crew announcement.","tips":["Facts first: down five days minimum, parts land Thursday.","The question they actually have is about their hours — answer it explicitly.","No forced silver linings; a straight answer is the reassurance."],"focus":["clarity","audience"],"placeholder":"Line 2 is down at least five days — the gearbox failed and parts arrive Thursday. Nobody loses hours: we're pulling the PM backlog forward and Line 1 adds a half-crew."},
    {"id":"hard-mfg-mid-21","level":"mid","profession":"industrial","title":"Pushing back on the target","scenario":"The plant manager has set your line's next-quarter target at 15% above current output — with no new equipment, headcount, or overtime. You believe it's not achievable and saying yes politely means owning a miss you predicted. The pushback has to be professional and numbered.","task":"Write the 3-sentence pushback: what you can commit to, the gap, and what closing it requires.","tips":["Lead with the commit, not the complaint: 8% is real with current changeover work.","Quantify the gap and its price: the last 7 points need the second setup tech or 6 hours of OT weekly.","Make it their choice with open eyes — that's the point of the pushback."],"focus":["impact","structure"],"placeholder":"I can commit to 8% with the changeover gains — the full 15% needs either the second setup tech or standing Saturday OT, and I'd rather you choose that tradeoff now than hear excuses in June."},
    {"id":"hard-mfg-mid-22","level":"mid","profession":"industrial","title":"The lockout confrontation","scenario":"You just watched a contractor reach into the conveyor with the disconnect thrown but no lock applied. Nobody's hurt. This conversation happens now, at the machine, in front of whoever's nearby — and it has to be unmissable without being a humiliation.","task":"Script the 3-sentence on-the-spot conversation: stop, the standard, and what happens next.","tips":["Immediate and specific: stop — that disconnect isn't locked.","The standard, not your anger: every energy source, locked and tagged, every time.","Escalation stated as fact, not threat: this gets documented, and here's why it must."],"focus":["clarity","impact"]},
    {"id":"hard-mfg-mid-23","level":"mid","profession":"industrial","title":"The no with an alternative","scenario":"The Line 4 supervisor wants to borrow your setup tech for their Thursday changeover marathon. Thursday is your export-die day — the one job that genuinely needs him. A flat no strains a relationship you rely on weekly.","task":"Write the 2-sentence response: the clean no for Thursday, and the alternative you can actually offer.","tips":["No to the specific thing, not the person: Thursday's impossible, and here's exactly why.","The alternative must be real: he's yours Friday morning, or Marcus can cover the simpler dies Thursday.","Keeping the trade explicit keeps the favor economy alive."],"focus":["clarity","structure"],"placeholder":"Can't do Thursday — that's the export die and Dev's the only certified setup on it. He's yours Friday morning, or Marcus can handle your standard dies Thursday."},
    {"id":"hard-mfg-mid-24","level":"mid","profession":"industrial","title":"Un-softening the feedback","scenario":"Your draft feedback note reads: 'You're doing great overall, and this is honestly a small thing, and I know everyone does it sometimes, but maybe try to watch the label alignment a bit when you get a chance.' The alignment issue caused a customer complaint. The softening has erased the message.","task":"Rewrite the feedback in 2 sentences: specific, serious as it deserves, and actionable.","tips":["Delete every 'small thing' disclaimer that contradicts the truth.","Anchor to the consequence: this reached a customer.","One behavior, one standard: check alignment at every roll change."],"focus":["clarity","concision"],"placeholder":"The label misalignment on Tuesday's run reached a customer as a complaint — it's not a small thing. Check alignment at every roll change; it takes ten seconds and it's the fix."},
    {"id":"hard-mfg-mid-25","level":"mid","profession":"industrial","title":"The quality escape, with a path forward","scenario":"You've confirmed that roughly 300 under-torqued units shipped to the distributor before the drift was caught. The message to the plant manager is the worst kind: the problem is out the door. It needs the full weight of that, and a plan, in the same breath.","task":"Write the 3-sentence message: the escape, the exposure, and the containment plan with times.","tips":["No preamble: about 300 under-torqued units shipped Tuesday and Wednesday.","The exposure honestly bounded: lot numbers known, one distributor, product traceable.","The plan with clock times: distributor call by 2, hold-and-sort by tomorrow, root cause Friday."],"focus":["structure","impact"],"placeholder":"About 300 under-torqued units shipped to Halton Distribution Tuesday and Wednesday — lot-traceable, single destination. I'm calling their receiving manager by 2 to hold the pallets, and we'll have sort results tomorrow."}
  ],
  "putting-it-together": [
    {"id":"together-mfg-mid-01","level":"mid","profession":"industrial","title":"The complete end-of-shift report","scenario":"Everything in one: your shift hit 96% of plan, the labeler ran on a temporary fix, one near-miss got logged, and QC owes you a disposition by 9 a.m. The incoming supervisor and the plant manager both read this — one standing up, one over coffee.","task":"Write the full 4-5 line report: headline first, ranked by what the reader must act on.","tips":["Line one is the thing that can bite tonight: the labeler's temporary fix.","Plan attainment in one clause; it's context, not news.","Every line either informs a decision or gets cut."],"focus":["structure","concision"],"placeholder":"1) Labeler is on a temporary clamp fix — watch it, Denny's in at 6. 2) 96% of plan (402/420)."},
    {"id":"together-mfg-mid-02","level":"mid","profession":"industrial","title":"The 90-second downtime brief","scenario":"The plant manager has given you 90 seconds at their desk on this morning's four-hour outage. Everything you've trained: verdict first, structure signposted, numbers precise, recommendation owned. No notes in hand.","task":"Script the full brief: what happened, cost, cause, fix, and your one ask — in about 90 spoken seconds.","tips":["Open with the frame: four hours lost, root cause found, one decision needed.","Numbers, not adjectives, throughout.","Land on the ask and stop talking."],"focus":["structure","impact"]},
    {"id":"together-mfg-mid-03","level":"mid","profession":"industrial","title":"The one-page proposal opening","scenario":"Your pre-staged tooling proposal gets one page in front of the plant manager and the controller. The opening paragraph decides whether the rest gets read: it needs the problem's size, the fix, the cost, and the return — in four sentences.","task":"Write that opening paragraph.","tips":["Sentence one: the problem in the reader's units — a shift a week of lost capacity.","The fix and its cost in one sentence each.","The return closes the paragraph and opens their appetite for the detail."],"focus":["structure","impact"],"placeholder":"Changeovers cost this plant a full shift of capacity every week. Pre-staged tooling — one cart and one checklist per line — cuts that 40%, as our Line 2 pilot proved in June."},
    {"id":"together-mfg-mid-04","level":"mid","profession":"industrial","title":"The complete quality-hold notice","scenario":"You're holding 1,600 units of the export SKU on a seal-strength question. Quality, planning, the plant manager, and customer service all read this one message — each needing something different from it. One message must serve all four.","task":"Write the full 4-5 sentence hold notice.","tips":["Headline: what's held, how much, why — everyone needs that.","Then one sentence each: disposition path (quality), schedule impact (planning), customer exposure (CS).","Label what's confirmed versus suspected — mixed audiences punish sloppiness there."],"focus":["clarity","structure"],"placeholder":"I've held 1,600 units of the export SKU pending seal-strength verification — samples pulled hourly after 11 a.m. tested borderline. Disposition test results land tomorrow noon."},
    {"id":"together-mfg-mid-05","level":"mid","profession":"industrial","title":"The incident notification chain","scenario":"An operator took a laceration requiring stitches at the trimmer twenty minutes ago. Three messages leave your phone in the next ten minutes: the plant manager (call), HSE (written), the crew (huddle at shift change). Same facts, three shapes.","task":"Write the plant-manager call script and the HSE written notification — 2-3 sentences each.","tips":["The call: injury, severity, status, next step — facts before feelings, calm before detail.","The written version adds precision: time, machine, task being performed, witnesses.","Neither speculates on cause — that's the investigation's job."],"focus":["structure","precision"]},
    {"id":"together-mfg-mid-06","level":"mid","profession":"industrial","title":"The 60-second tier update","scenario":"The daily tier meeting: 60 seconds for your line, plant manager and peers listening. Today you have a hit plan, a developing bearing issue, one open quality disposition, and a staffing gap Thursday. Four items, one minute, ranked.","task":"Write the update in 4 lines, one per item, most decision-relevant first.","tips":["The bearing gets the lead — it's the item someone can act on today.","'Plan hit' is three words, not a story.","End with your ask: coverage for Thursday."],"focus":["concision","structure"],"placeholder":"One flag: the main-drive bearing crossed its vibration threshold — I need the Sunday PM window confirmed today."},
    {"id":"together-mfg-mid-07","level":"mid","profession":"industrial","title":"The long-weekend handover document","scenario":"You're off for four days and your relief is a supervisor borrowed from another area who doesn't know your line. The handover doc must carry everything you'd normally say in person: risks ranked, contacts named, decisions pre-made where possible.","task":"Write the doc's first section: the top 3 things that can go wrong and the pre-made decision for each.","tips":["Rank by likelihood times damage, not by topic.","Pre-decide: 'if the wrapper faults twice in a shift, call Denny — don't keep resetting it.'","Names and numbers inline, not 'see contact list.'"],"focus":["structure","audience"]},
    {"id":"together-mfg-mid-08","level":"mid","profession":"industrial","title":"Same news, two rooms","scenario":"The gearbox failure takes Line 2 down for five days. You'll tell the plant manager (cost, recovery, customer exposure) and the crew (their hours, their week) — same facts, entirely different messages. Writing both exposes whether you actually know your audiences.","task":"Write both versions, 2-3 sentences each.","tips":["The plant manager's version leads with output and customer impact.","The crew's version leads with what happens to their hours.","Neither version spins — they differ in emphasis, never in facts."],"focus":["audience","clarity"]},
    {"id":"together-mfg-mid-09","level":"mid","profession":"industrial","title":"The capital summary paragraph","scenario":"The capital committee reads one summary paragraph per request before deciding which get presentations. Yours is the $28k palletizer gate. Number-led, recommendation-owned, objection-anticipated — the whole course in five sentences.","task":"Write the summary paragraph.","tips":["Payback and safety numbers in the first sentence.","Own it: 'I recommend' — committees fund conviction backed by math.","Spend one sentence on the obvious objection: why now, why this option."],"focus":["precision","impact"],"placeholder":"I recommend the $28k palletizer safety gate: it pays back in 14 months from reduced manual handling and eliminates the station behind two of our three lifting injuries last year."},
    {"id":"together-mfg-mid-10","level":"mid","profession":"industrial","title":"The audit response opening","scenario":"The customer audit closed with two findings on your area, and your written response goes to their quality team with your plant manager copied. The opening paragraph sets the tone: no defensiveness, no groveling — ownership, precision, and dated commitments.","task":"Write the response's opening 3 sentences.","tips":["Accept the findings plainly in sentence one if they're accurate.","Each finding gets an owner and a date, not a philosophy.","The tone target: a supplier they trust more after the finding than before it."],"focus":["structure","precision"],"placeholder":"Both findings are accurate and we accept them. The first-off documentation gap closes June 20 with the interlocked sign-off; the calibration filing gap closes June 15 when tracking moves into the CMMS."},
    {"id":"together-mfg-mid-11","level":"mid","profession":"industrial","title":"Self-edit against the checklist","scenario":"Here's a draft to the plant manager: 'Just wanted to touch base regarding the situation with Line 3. There have been some issues with the new sensor setup that we've been kind of working through, and while things are mostly okay, we might potentially see some impact on the numbers this week, so I just wanted to flag it.' Run the full rubric on it.","task":"Rewrite the message: point first, precise, hedges cut, action named.","tips":["Find the buried point: Line 3 may miss this week because the sensor retrofit is misfiring.","Replace 'some issues' and 'some impact' with counts.","End with what you're doing and when they'll know more."],"focus":["concision","clarity"],"placeholder":"Line 3 may run 200-300 units short this week — the new sensors are false-tripping about once an hour. Vendor tech is on-site tomorrow; I'll confirm impact by Wednesday."},
    {"id":"together-mfg-mid-12","level":"mid","profession":"industrial","title":"Pick the channel","scenario":"Four messages sit in your queue: the bearing PM needs the plant manager's approval today; an operator needs feedback on a repeated error; the crew needs to hear about next month's schedule change; maintenance needs the fault history for tomorrow. Radio, text, email, face-to-face, huddle — each message has a right channel.","task":"Assign each message a channel and justify each in one line.","tips":["Urgency plus a decision equals synchronous — walk to the office.","Feedback is face-to-face, always; the record can follow in writing.","History and data travel by email, where they can be searched later."],"focus":["audience","structure"]},
    {"id":"together-mfg-mid-13","level":"mid","profession":"industrial","title":"The Friday-slip message, complete","scenario":"The full package in one message: order 8802 slips from Friday to Tuesday (hard news), because the rework consumed the buffer (cause), recovery is already running (plan), and sales needs to know what to tell the customer (audience). BLUF plus hard-message discipline plus precision.","task":"Write the complete 4-sentence message to sales, plant manager copied.","tips":["The slip and the new date in sentence one — no runway.","Cause in one factual sentence, no defensiveness.","Close with what's firm and what sales can commit to."],"focus":["clarity","impact"],"placeholder":"Order 8802 moves from Friday to Tuesday — firm. The seal rework consumed our schedule buffer; the batch passed final inspection this morning and is in packaging now."},
    {"id":"together-mfg-mid-14","level":"mid","profession":"industrial","title":"The monthly report opening","scenario":"Your line's monthly report goes to plant leadership. The month: output 102% of plan, scrap down to 2.1%, one recordable injury, and the changeover project delivering ahead of pace. The opening paragraph must find the story, not list the metrics.","task":"Write the 3-sentence opening that leads with the month's real story.","tips":["Decide the headline: the recordable is the story leadership will care about — don't bury it under the good numbers.","Good metrics can share one sentence.","Close the paragraph with where the month leaves you for next month."],"focus":["structure","precision"]},
    {"id":"together-mfg-mid-15","level":"mid","profession":"industrial","title":"The full toolbox talk","scenario":"Ninety seconds at shift start, whole crew, on the pallet near-miss from last week. Structure, audience, one behavior, no lecture. This is the spoken form of everything the course teaches: attention earned in ten seconds, one point, one ask.","task":"Script the complete 90-second talk.","tips":["Open with the event, concrete and close to home.","One lesson, one behavior — a talk that asks for three things gets zero.","End by checking understanding, not by trailing off."],"focus":["audience","impact"]},
    {"id":"together-mfg-mid-16","level":"mid","profession":"industrial","title":"The escalation with the owned recommendation","scenario":"Third failed fix on the wrapper; you're escalating to the plant manager with everything: the history (structured), the cost (precise), the options (weighed), and your recommendation (owned). One message that shows the whole toolkit.","task":"Write the complete 5-sentence escalation.","tips":["Frame first: fourth failure in six weeks, $9k of downtime so far, decision needed.","History compressed to one sentence — it's context, not the point.","Your recommendation with its cost, then the alternative you rejected and why."],"focus":["impact","structure"],"placeholder":"The wrapper has now failed four times in six weeks — about $9k in downtime — and I'm recommending we stop patching it. The $14k drive replacement fixes the root cause; another patch is $2k with a 50% chance we're back here in a month."},
    {"id":"together-mfg-mid-17","level":"mid","profession":"industrial","title":"Write it, then halve it","scenario":"Write your update on the resin trial in full — status, results, next steps — then cut it to half its word count without losing a fact. The first version is for you; the second is what you send. The gap between them is your padding profile.","task":"Write both versions: the full 6-sentence update, then the 3-sentence cut.","tips":["Write freely first; edit ruthlessly second.","Cut narrative connectors — 'as a result of this' — before cutting facts.","Notice what you cut: that's what you always over-include."],"focus":["concision","impact"]},
    {"id":"together-mfg-mid-18","level":"mid","profession":"industrial","title":"The promotion case","scenario":"You're recommending your lead hand for the open supervisor role on C shift. The case goes to the plant manager in writing: specific evidence, honest gaps, owned recommendation. Vague praise gets skimmed; a structured case gets a decision.","task":"Write the 4-sentence case: the recommendation, two evidence points with numbers, and the honest gap with your plan for it.","tips":["Recommend first, then prove it.","Evidence is counted: ran the line solo for 11 shifts, trained four operators to sign-off.","Naming the gap — and the development plan — makes the praise believable."],"focus":["impact","precision"],"placeholder":"I recommend Priya for the C-shift supervisor role. She ran this line solo for 11 shifts across my absences with zero misses, and she took four new operators to certification this year."},
    {"id":"together-mfg-mid-19","level":"mid","profession":"industrial","title":"The day everything went wrong","scenario":"Today: a two-hour outage, a quality hold, a staffing callout, a near-miss, and a missed changeover window. Your end-of-day summary to the plant manager cannot be five stories. Triage is the skill: what do they need, in what order, in under 100 words.","task":"Write the summary, ranked, under 100 words.","tips":["Rank by what needs their awareness or action — probably the hold, then the near-miss.","Items with no decision needed compress to a clause.","'Handled' is a complete status for half of it."],"focus":["structure","concision"]},
    {"id":"together-mfg-mid-20","level":"mid","profession":"industrial","title":"The vendor escalation package","scenario":"The resin supplier's quality manager gets your formal escalation: the defect record (precise), the cost (quantified), the standard violated (cited), and the resolution you require with a deadline (owned). Everything in one message that could end up on their VP's desk.","task":"Write the complete 4-5 sentence escalation.","tips":["Lead with the requirement and the deadline — it's an escalation, not an update.","Every claim carries its number: lots, dates, reject rates.","Professional heat: no adjectives, all facts, firm close."],"focus":["precision","impact"],"placeholder":"We require a corrective action plan for the recurring short-shot defects by June 25, or we begin qualifying an alternate supplier. Lots 7741, 7756, and 7803 ran 6-9% scrap on our line against your 1% commitment."},
    {"id":"together-mfg-mid-21","level":"mid","profession":"industrial","title":"Walking the VP down the line","scenario":"The regional VP tours your line Thursday: ten minutes, three stops. Each stop gets 90 seconds: what they're looking at, why it matters, one number that sticks. A tour script is audience calibration in its purest form.","task":"Script the three stops, 2-3 sentences each.","tips":["Each stop: what it is, the number that makes it interesting, the one thing you're doing about it.","VPs remember one number per stop — choose it deliberately.","End the tour on your best story, not wherever you happen to be standing."],"focus":["audience","structure"]},
    {"id":"together-mfg-mid-22","level":"mid","profession":"industrial","title":"The new-SOP rollout message","scenario":"The revised changeover SOP goes live Monday. Your announcement must cover: what changes (precise), why (persuasive), from when (clear), and what happens to questions or problems (owned). Every rollout that skips one of those four generates a week of confusion.","task":"Write the 4-sentence rollout message to all three crews.","tips":["What changes, concretely: the die-cart staging step moves before shutdown, not after.","One sentence of why, in crew currency: it's the 20 minutes we stopped losing in the pilot.","Name the question path: problems go to your lead, logged, answered within a day."],"focus":["clarity","audience"],"placeholder":"Starting Monday, die-cart staging happens BEFORE line shutdown, not after — that one change saved the pilot crew 20 minutes per changeover."},
    {"id":"together-mfg-mid-23","level":"mid","profession":"industrial","title":"The year-end line summary","scenario":"Your line's year in one paragraph for the plant review: output up 4%, scrap halved, two recordables against four last year, the changeover project's 40% gain, and the aging press as next year's risk. The whole course applies: story, precision, structure, and a forward point.","task":"Write the 4-5 sentence summary paragraph.","tips":["Find the year's one-line story first, then support it.","Each claim keeps its number — a summary isn't a place for 'significantly.'","End forward: the press is next year's sentence, not a footnote."],"focus":["precision","structure"],"placeholder":"Line 2's year in one line: more output, half the scrap, and the changeover problem solved. Output rose 4% on flat headcount, scrap fell from 4.2% to 2.1%, and recordables halved to two."},
    {"id":"together-mfg-mid-24","level":"mid","profession":"industrial","title":"Ending the reply-all storm","scenario":"An email thread about the mislabeled pallet has hit fourteen replies across five departments, three competing theories, and two proposed process changes. Nobody has stated the facts, the owner, or the next step. One message can end it — yours.","task":"Write the 3-4 sentence thread-ending message.","tips":["Restate the established facts in two sentences — most of the thread is people missing them.","Name the single owner and the single next step with a time.","Close the loop explicitly: 'further findings go to me directly, and I'll summarize Friday.'"],"focus":["clarity","concision"],"placeholder":"Summarizing where this stands: one pallet, 48 cases, mislabeled at the printer between 2 and 3 p.m. Tuesday — recovered before shipping. I own the fix; label verification goes into the changeover checklist today."},
    {"id":"together-mfg-mid-25","level":"mid","profession":"industrial","title":"The capstone message","scenario":"One message, all constraints: the plant manager, five sentences maximum. Content: this quarter's changeover project results, the next investment you're recommending, its cost and payback, the one risk, and the decision you need by Friday. Point first, numbers throughout, recommendation owned, no hedges.","task":"Write the five-sentence capstone message.","tips":["Sentence one carries the result and the ask together if you can manage it.","Audit yourself after: any adjective doing a number's job?","Read it aloud once — the ear catches what the eye forgives."],"focus":["structure","impact"],"placeholder":"The changeover project finished the quarter at a 41% time reduction — a shift of capacity recovered every week. I'm recommending we extend it to Lines 3 and 4 for $9k in carts and fixtures, paying back in seven weeks."}
  ],
};
